"""
High-Performance Backup Worker - Mass Backup Processing

Features:
- Server-Side Copy for OneDrive/SharePoint files (zero server load)
- Storage sharding across multiple Azure Storage Accounts
- Workload parallelism (Exchange, OneDrive, SharePoint concurrently)
- User-level parallelism with configurable concurrency
- Delta token tracking for incremental backups
- Adaptive throttling with exponential backoff
- Content deduplication via SHA-256
- Versioned blob paths for retention management

Architecture:
  Files > 10MB: Graph API → @downloadUrl → Azure Server-Side Copy (fastest)
  Files < 10MB: Graph API → Python SDK → Azure Blob (efficient for small items)
  Emails/Chats: Graph API → Python SDK → Azure Blob (JSON/MIME processing)
"""
import asyncio
import json
import re
import uuid
import hashlib
import logging
import os
import tempfile
from datetime import datetime, timedelta, timezone
import time
from typing import Dict, List, Any, Optional, Set, Tuple


# orjson is ~5-10× faster than stdlib json for payload-heavy paths like
# per-chat-message persistence. Defensive import so deployments without
# the package still work — falls back transparently.
try:
    import orjson as _fast_json  # type: ignore

    def _json_dumps_bytes(obj) -> bytes:
        return _fast_json.dumps(obj, default=str)
except ImportError:
    import json as _stdlib_json

    def _json_dumps_bytes(obj) -> bytes:
        return _stdlib_json.dumps(obj, default=str).encode("utf-8")


# BLAKE3 is ~7-10× faster than SHA-256 on modern CPUs (no SHA-NI needed,
# uses SIMD everywhere). Same 256-bit digest length as SHA-256 so the
# DB column stays the same size. We use it ONLY for the per-item
# integrity hash (content_hash) where there is no cross-release
# comparison concern.
#
# content_checksum (used by the idx_snapshot_items_tenant_checksum
# cross-snapshot dedup index) still uses SHA-256 on the file/attachment
# paths so existing dedup doesn't silently break. Inline items (chat
# msgs, mail bodies) set content_checksum=None because Graph's own
# message id is the real dedup key — no value in hashing the JSON
# payload for those.
try:
    from blake3 import blake3 as _blake3  # type: ignore

    def _fast_hash_hex(body: bytes) -> str:
        return _blake3(body).hexdigest()
except ImportError:
    import hashlib as _stdlib_hash

    def _fast_hash_hex(body: bytes) -> str:
        return _stdlib_hash.sha256(body).hexdigest()


# Chunk size for multi-row INSERTs. 2000 rows × ~2 KB each keeps a single
# statement well under Postgres' 1 GB protocol limit while being large
# enough to amortize per-statement overhead (10-50× faster than per-row
# ORM add_all at these sizes). Tunable via env for huge mailboxes.
_BULK_INSERT_CHUNK = int(os.getenv("BULK_INSERT_CHUNK", "2000"))


# Inline-attachment threshold. Attachments + chat hosted-contents below
# this size go into snapshot_items.extra_data["inline_b64"] (base64-
# encoded bytes) instead of Azure Blob. Two reasons:
#   1. Each Azure block-list commit costs 200-500 ms fixed overhead.
#      Most enterprise attachments are signatures, logos, thumbnails
#      ≤256 KB — paying a half-second round-trip per tiny image is the
#      single biggest per-email wall-time tax (~10s/email observed).
#   2. The azure-storage-blob aiohttp transport intermittently raises
#      `Timeout on reading data from socket` under high concurrency for
#      sub-MB uploads against newly-created containers (observed on
#      catt_* chat hosted-content uploads). Inlining sidesteps the bug.
# Trade-off: small items skip cross-snapshot dedup (find_existing_blob
# only matches blob-backed rows). Dedup pool's `min_size_bytes` default
# is 1 KB so tiny items already weren't deduped; impact is bounded to
# the 1KB-256KB band, typically <2% of total backup bytes.
_INLINE_ATTACHMENT_MAX_BYTES = int(
    os.getenv("INLINE_ATTACHMENT_MAX_BYTES", str(256 * 1024)),
)


def _maybe_inline_attachment(content_bytes: Optional[bytes]) -> Optional[str]:
    """Return base64-encoded content if it fits the inline threshold;
    None if the bytes should go to Azure Blob instead.

    Callers MUST handle both branches — inline path sets
    extra_data["inline_b64"] and leaves blob_path=None; blob path runs
    the existing upload_blob_with_dedup flow.
    """
    if content_bytes is None:
        return None
    if len(content_bytes) > _INLINE_ATTACHMENT_MAX_BYTES:
        return None
    import base64 as _b64
    return _b64.b64encode(content_bytes).decode("ascii")


def _parse_mime_inline_parts(mime_bytes: bytes) -> List[Dict[str, Any]]:
    """Walk an RFC822 MIME tree and return the inline parts keyed by
    Content-ID. Used to recover cid:-referenced inline images that
    Graph's /messages/{id}/attachments endpoint doesn't expose
    (Teams activity notifications, OneDrive shares, Planner emails
    are the common culprits).

    Returns a list of dicts:
        {
          "content_id":   "abc123" (no angle brackets, lowercased),
          "content_type": "image/jpeg",
          "filename":     "image001.jpg" or None,
          "payload":      <bytes>,
        }

    Decoding of base64 / quoted-printable transfer encodings is handled
    by `email.message_from_bytes(...).get_payload(decode=True)`. Parts
    without Content-ID, without a decodable payload, or whose payload
    is empty are filtered out — the caller only wants real binary
    inline parts.
    """
    import email as _email
    from email.policy import default as _default_policy

    try:
        msg = _email.message_from_bytes(mime_bytes, policy=_default_policy)
    except Exception:
        return []

    out: List[Dict[str, Any]] = []
    for part in msg.walk():
        try:
            cid_header = part.get("Content-ID")
        except Exception:
            cid_header = None
        if not cid_header:
            continue
        cid = str(cid_header).strip().strip("<>").strip().lower()
        if not cid:
            continue
        try:
            payload = part.get_payload(decode=True)
        except Exception:
            payload = None
        if not payload:
            continue
        try:
            ct = part.get_content_type()
        except Exception:
            ct = "application/octet-stream"
        try:
            fname = part.get_filename()
        except Exception:
            fname = None
        out.append({
            "content_id": cid,
            "content_type": ct or "application/octet-stream",
            "filename": fname,
            "payload": payload,
        })
    return out


def _extract_cid_refs_from_body(body_html: str) -> Set[str]:
    """Pull every `cid:<id>` reference out of an HTML email body,
    return as a set of lowercase ids (no angle brackets). Used to
    compute which inline references the regular attachment fetch
    didn't resolve, so the MIME fallback only does work for the
    actual gaps.
    """
    if not body_html:
        return set()
    import re as _re
    out: Set[str] = set()
    # Matches src="cid:..." / src='cid:...' / src=cid:... with or
    # without angle brackets. Reuses the same shape as the frontend
    # rewrite regex (Recovery.tsx:215) so the worker and reader stay
    # symmetric.
    for m in _re.finditer(
        r'(?:src|background)\s*=\s*["\']?cid:<?([^"\'>\s)]+?)>?["\']?',
        body_html, _re.IGNORECASE,
    ):
        cid = m.group(1).strip().lower()
        if cid:
            out.add(cid)
    return out


class SnapshotVanishedError(Exception):
    """Raised by the snapshot_items bulk insert when the parent snapshot
    row was deleted out from under us — typically because cancel_job's
    revert helper, an admin purge, or stale-snapshot cleanup removed it
    while a long-running handler (chats, mail, onedrive) was still
    streaming items. Without this signal, every subsequent batch in the
    handler hits the same FK violation and the catch-all `except
    Exception` in each per-item loop logs hundreds of failures while
    burning Graph API quota for nothing. Handlers catch this once,
    abort the resource cleanly, and let the outer worker move on."""


class PoisonMessageError(Exception):
    """Raised by process_backup_message when the envelope is structurally
    invalid (missing jobId AND no recognised partition messageType).
    consume_queue catches this and rejects the message with
    requeue=False so it lands in the DLQ instead of looping forever.
    Classic queues don't auto-increment x-delivery-count on plain
    requeue, so the existing max-retries gate never trips for such
    messages — without an explicit poison signal a single malformed
    payload pins a consumer indefinitely (2026-05-16 incident)."""


async def _bulk_upsert_snapshot_items(
    session, rows: List[Dict[str, Any]],
) -> int:
    """Insert snapshot_items rows in chunked multi-row INSERTs with
    ON CONFLICT DO NOTHING on (snapshot_id, external_id).

    Replaces the legacy session.add_all + commit loop which serialized
    12k rows into 12k separate SQL statements — dominated wall time on
    chat-heavy users (~15-20s for 12k msgs). Multi-row pg_insert with
    the UNIQUE idempotency guard both speeds up the path ~10× and makes
    message redelivery safe (race-inserted duplicates silently skipped).

    Returns the number of rows attempted (not necessarily inserted —
    conflicts are dropped silently by design).

    Raises SnapshotVanishedError if the FK to snapshots fails — see the
    class doc; other IntegrityError subtypes (tenant_id FK, unexpected
    constraints) re-raise unchanged.
    """
    if not rows:
        return 0
    from sqlalchemy.dialects.postgresql import insert as _pg_insert
    from sqlalchemy.exc import IntegrityError as _IntegrityError
    total = 0
    for i in range(0, len(rows), _BULK_INSERT_CHUNK):
        chunk = rows[i:i + _BULK_INSERT_CHUNK]
        # ON CONFLICT target must match an existing unique index column
        # set exactly. The snapshot_items unique index is
        # uq_snapshot_items_snap_ext_type on
        # (snapshot_id, external_id, item_type) — see shared/database.py:950.
        # A 2-column spec raises InvalidColumnReferenceError and rolls back
        # every batched insert, landing every bulk-backup with 0 items.
        stmt = _pg_insert(SnapshotItem).values(chunk).on_conflict_do_nothing(
            index_elements=["snapshot_id", "external_id", "item_type"],
        )
        try:
            await session.execute(stmt)
        except _IntegrityError as e:
            # Detect "parent snapshot row deleted mid-flight" specifically
            # and surface as SnapshotVanishedError so handlers can break
            # cleanly. Match on the FK constraint name, not the message
            # text, to stay robust across asyncpg / driver wording.
            if "snapshot_items_snapshot_id_fkey" in str(e):
                await session.rollback()
                snap_id = chunk[0].get("snapshot_id") if chunk else None
                raise SnapshotVanishedError(
                    f"snapshot {snap_id} no longer exists; aborting handler"
                ) from e
            raise
        total += len(chunk)
    await session.commit()
    return total


# ==================== mail_message_bodies helpers (cross-user dedup) ====================
#
# Item B: Mirror of the chat_thread_messages dedup pattern, applied to
# mail. Tenant-scoped table keyed by (tenant_id, fingerprint). Phase 1
# is a write-only dual-write — the body still lands in
# snapshot_items.extra_data['raw'] so restore paths don't change.
# Future Phase 2 will JOIN here and stop the inline write.

def _mail_message_fingerprint(msg: Dict[str, Any]) -> str:
    """Stable per-tenant dedup key for a Graph message.

    Outlook gives each mailbox its own message.id even for the same
    logical email, so we can't dedup on Graph id. We hash a tuple
    that is (in practice) unique per logical message:

      from_addr | sent_iso | subject | content_size | first 64KB body sha256

    sent_date_time is microsecond-precise on Graph payloads; combined
    with from + subject it discriminates well past mailbox boundaries.
    The body-prefix hash guards against the rare case where two
    different replies have identical headers (Outlook generates
    "Re:" + same minute + same sender + same subject when you reply
    twice in 30 seconds with different bodies).
    """
    sender = ""
    fr = (msg.get("from") or {}).get("emailAddress") or {}
    if isinstance(fr, dict):
        sender = (fr.get("address") or "").lower()
    sent = str(msg.get("sentDateTime") or "")
    subj = (msg.get("subject") or "")[:512]
    body = (msg.get("body") or {})
    body_text = body.get("content") if isinstance(body, dict) else ""
    body_text = body_text or ""
    body_size = len(body_text)
    # First 64KB only — large attached HTML bodies don't need full hashing.
    prefix_hash = hashlib.sha256(body_text[:65536].encode("utf-8", errors="replace")).hexdigest()
    key = f"{sender}|{sent}|{subj}|{body_size}|{prefix_hash}"
    return hashlib.sha256(key.encode("utf-8")).hexdigest()


def _parse_graph_iso_dt(s) -> Optional[datetime]:
    """Convert Graph API ISO-8601 timestamp string to datetime.datetime.

    Graph returns strings like ``2025-03-10T04:32:42Z`` or
    ``2025-03-10T04:32:42.1234567Z``. asyncpg requires a real datetime
    object for TIMESTAMPTZ columns. Returns None on parse failure so
    the dedup-table insert can still proceed with a NULL timestamp
    rather than aborting the whole row.
    """
    if s is None:
        return None
    if isinstance(s, datetime):
        return s
    if not isinstance(s, str):
        return None
    raw = s.strip()
    if not raw:
        return None
    try:
        # Python 3.11+ fromisoformat handles trailing Z and fractional
        # seconds with up to 6 digits. Truncate >6-digit fractions
        # (Graph occasionally emits 7) which would otherwise raise.
        if raw.endswith("Z"):
            raw = raw[:-1] + "+00:00"
        # Cap fractional seconds at 6 digits (Python's max for datetime).
        if "." in raw and "+" in raw:
            base, tz = raw.rsplit("+", 1)
            if "." in base:
                head, frac = base.rsplit(".", 1)
                base = head + "." + frac[:6]
            raw = base + "+" + tz
        return datetime.fromisoformat(raw)
    except (ValueError, TypeError):
        return None


async def _bulk_upsert_mail_message_bodies(
    session, tenant_id, user_id: str, snapshot_id, messages: List[Dict[str, Any]],
) -> int:
    """Bulk-insert mail_message_bodies rows with ON CONFLICT DO NOTHING.

    Phase 1 dual-write: caller still writes the full body to
    snapshot_items.extra_data['raw']. This function adds a parallel
    dedup record so we can measure the cross-user hit ratio in prod
    before flipping reads in Phase 2.

    Errors are caught and logged but do NOT abort the snapshot — this
    is best-effort optimization metadata.
    """
    if not messages:
        return 0
    try:
        from sqlalchemy.dialects.postgresql import insert as _pg_insert
        from shared.models import MailMessageBody as _MMB
        rows: List[Dict[str, Any]] = []
        seen_fp: set = set()
        for m in messages:
            if not isinstance(m, dict):
                continue
            try:
                fp = _mail_message_fingerprint(m)
            except Exception:
                continue
            if fp in seen_fp:
                continue
            seen_fp.add(fp)
            body = (m.get("body") or {}) if isinstance(m.get("body"), dict) else {}
            from_obj = (m.get("from") or {}).get("emailAddress") or {}
            if not isinstance(from_obj, dict):
                from_obj = {}
            body_content = body.get("content")
            body_type = body.get("contentType")
            content_size = len((body_content or "").encode("utf-8", errors="replace")) if body_content else 0
            content_hash = (
                hashlib.sha256((body_content or "").encode("utf-8", errors="replace")).hexdigest()
                if body_content else None
            )
            rows.append({
                "id": uuid.uuid4(),
                "tenant_id": tenant_id,
                "fingerprint": fp,
                "first_user_id": user_id,
                "first_snapshot_id": snapshot_id,
                "from_user_id": user_id,
                "from_address": (from_obj.get("address") or "")[:256] or None,
                "from_display_name": (from_obj.get("name") or "")[:256] or None,
                "subject": m.get("subject"),
                # Graph returns ISO-8601 strings; asyncpg requires datetime
                # objects for TIMESTAMPTZ columns. Parse on insert, NULL on
                # parse failure (better than the whole batch failing).
                "sent_date_time": _parse_graph_iso_dt(m.get("sentDateTime")),
                "received_date_time": _parse_graph_iso_dt(m.get("receivedDateTime")),
                "body_content": body_content,
                "body_content_type": (body_type or "")[:16] or None,
                "has_attachments": m.get("hasAttachments"),
                "metadata_raw": m,
                "content_hash": content_hash,
                "content_size": content_size,
                "ref_count": 1,
            })
        if not rows:
            return 0
        # Chunked insert — same chunk size as snapshot_items for parity.
        total = 0
        for i in range(0, len(rows), _BULK_INSERT_CHUNK):
            chunk = rows[i:i + _BULK_INSERT_CHUNK]
            stmt = _pg_insert(_MMB).values(chunk).on_conflict_do_nothing(
                index_elements=["tenant_id", "fingerprint"],
            )
            await session.execute(stmt)
            total += len(chunk)
        await session.commit()
        return total
    except Exception as e:
        # Best-effort. Don't fail a snapshot over a dedup-table issue.
        try:
            await session.rollback()
        except Exception:
            pass
        print(f"[MAIL_DEDUP] bulk upsert failed (continuing): {type(e).__name__}: {e}")
        return 0


# ==================== chat_threads helpers (cross-user dedup) ====================
#
# These helpers implement the tenant-singleton chat-thread store (see
# shared/models.py ChatThread / ChatThreadMessage). The unit of dedup
# is (tenant_id, chat_id): User B's USER_CHATS run for a chat that User A
# just drained within the freshness window short-circuits and reuses
# A's messages, writing only thin pointer rows into snapshot_items for
# B's snapshot.

_CHAT_THREAD_DRAIN_FRESHNESS_S = int(
    os.getenv("CHAT_THREAD_DRAIN_FRESHNESS_S", "25200"),
)


# OneDrive per-file retry queue classifier. The producer (per-file
# gather in _useronedrive_backup_files) calls this on each failure
# string to decide whether to enqueue the file for retry. Permanent
# errors are not retryable — re-trying a 404 / 410 / 403 wastes the
# consumer's Graph budget.
_ONEDRIVE_RETRY_PERMANENT_CODES = ("404", "410", "401", "403")
_ONEDRIVE_RETRY_THROTTLE_CODES = ("429", "503")


def _classify_onedrive_file_error(err_text: Optional[str]) -> str:
    """Return one of: "throttle", "stream_drop", "permanent", "unknown".

    Used by the OneDrive per-file retry queue to skip permanent
    failures (which would burn retry budget forever) and bias the
    initial next_retry_at by error class — throttled files get a
    longer base delay than stream drops.
    """
    if not err_text:
        return "unknown"
    low = err_text.lower()
    for code in _ONEDRIVE_RETRY_PERMANENT_CODES:
        if code in err_text:
            return "permanent"
    for code in _ONEDRIVE_RETRY_THROTTLE_CODES:
        if code in err_text:
            return "throttle"
    if (
        "remoteprotocolerror" in low or "readerror" in low
        or "readtimeout" in low or "stream dropped" in low
        or "writeerror" in low or "connecterror" in low
        or "timeout" in low
    ):
        return "stream_drop"
    return "unknown"


_HOSTED_CONTENT_URL_RE = re.compile(
    r"/messages/[^/\"'<>\s]+/hostedContents/[^/\"'<>\s]+/\$value"
)


def _msg_likely_has_hosted_content(m: Dict[str, Any]) -> bool:
    """Strict pre-check for whether a Graph chat message has inline
    hostedContents worth fetching.

    Only inline-image refs in a message's HTML body match the canonical
    Graph URL shape ``/messages/{mid}/hostedContents/{hid}/$value``.
    Quoted-reply HTML that merely echoes the substring "hostedContents"
    from a parent message does NOT match, avoiding a stampede of empty
    per-msg ``/hostedContents`` GETs that produced the slowdown after
    fix #2.
    """
    body = m.get("body") or {}
    if body.get("contentType") != "html":
        return False
    content = body.get("content") or ""
    if not isinstance(content, str) or not content:
        return False
    return bool(_HOSTED_CONTENT_URL_RE.search(content))


def _parse_iso_to_dt(s: Optional[str]) -> Optional[datetime]:
    """Parse a Graph ISO-8601 timestamp into a tz-aware ``datetime``.

    asyncpg refuses to bind string values into TIMESTAMPTZ columns even when
    the SQL has ``CAST(:x AS TIMESTAMPTZ)`` — the type check happens before
    the cast runs. Convert here so every helper that hits ``chat_threads``
    or ``chat_thread_messages`` passes a real datetime to the driver.

    Returns ``None`` on empty input or unparseable strings — the SQL uses
    ``COALESCE`` / ``CAST(:x AS TIMESTAMPTZ)`` patterns that tolerate NULL.
    """
    if s is None or s == "":
        return None
    if isinstance(s, datetime):
        return s
    try:
        # Python 3.11+ accepts trailing 'Z'; older versions need the swap.
        return datetime.fromisoformat(str(s).replace("Z", "+00:00"))
    except (ValueError, AttributeError, TypeError):
        return None


async def _claim_or_load_chat_thread(
    *,
    tenant_id: str,
    chat_id: str,
    chat_type: Optional[str],
    chat_topic: Optional[str],
    member_names: Optional[List[str]],
    last_updated_at_iso: Optional[str],
) -> Dict[str, Any]:
    """Atomically claim (tenant_id, chat_id) for drain or detect that a
    concurrent / recent backup already drained it.

    Uses ``INSERT … ON CONFLICT DO UPDATE … RETURNING (xmax = 0) AS inserted``
    so we get per-row mutual exclusion without an explicit FOR UPDATE.
    Multiple worker pods racing on the same chat: only one wins the claim;
    the rest see ``last_drained_at`` inside the freshness window and skip.

    Returns a dict with:
      * ``thread_id``         — chat_threads.id (UUID str). Always present.
      * ``claimed``           — True iff caller should drain. False = reuse
                                existing chat_thread_messages.
      * ``drain_cursor``      — last successful drain cursor (max
                                lastModifiedDateTime). May be None.
      * ``last_updated_at``   — last known chat.lastUpdatedDateTime
                                from a prior drain.
      * ``drain_failure_state`` — failure record from a prior backup or {}.
    """
    member_names_json = list(member_names or [])
    # Two-step in one statement: SELECT the prior row inside a WITH CTE so we
    # see the value of last_updated_at BEFORE the UPSERT overwrites it, then
    # do the UPSERT and JOIN them back together in the outer SELECT. PG
    # documents that the SELECT inside a data-modifying CTE observes the
    # pre-modification snapshot — exactly what we need to detect "this row
    # already existed with an older Graph timestamp."
    async with async_session_factory() as s:
        row = (await s.execute(
            text(
                "WITH prior AS ( "
                "  SELECT last_updated_at AS prior_lu "
                "    FROM chat_threads "
                "   WHERE tenant_id = :tid AND chat_id = :cid "
                "), "
                "upserted AS ( "
                "  INSERT INTO chat_threads "
                "    (tenant_id, chat_id, chat_type, chat_topic, member_names_json, "
                "     last_updated_at, last_drained_at, created_at, updated_at) "
                "  VALUES "
                "    (:tid, :cid, :ct, :tp, CAST(:mn AS JSONB), "
                "     CAST(:lu AS TIMESTAMPTZ), NULL, NOW(), NOW()) "
                "  ON CONFLICT (tenant_id, chat_id) DO UPDATE SET "
                "    chat_type         = COALESCE(EXCLUDED.chat_type, chat_threads.chat_type), "
                "    chat_topic        = COALESCE(EXCLUDED.chat_topic, chat_threads.chat_topic), "
                "    member_names_json = COALESCE(EXCLUDED.member_names_json, chat_threads.member_names_json), "
                "    last_updated_at   = COALESCE(EXCLUDED.last_updated_at, chat_threads.last_updated_at), "
                "    updated_at        = NOW() "
                "  RETURNING id, drain_cursor, last_updated_at, drain_failure_state, "
                "            last_drained_at, last_drained_msg_count, "
                "            (xmax = 0) AS inserted "
                ") "
                "SELECT u.id, u.drain_cursor, u.last_updated_at, u.drain_failure_state, "
                "       u.last_drained_at, u.last_drained_msg_count, u.inserted, "
                "       p.prior_lu "
                "  FROM upserted u "
                "  LEFT JOIN prior p ON TRUE"
            ),
            {
                "tid": tenant_id, "cid": chat_id, "ct": chat_type,
                "tp": chat_topic,
                "mn": json.dumps(member_names_json) if member_names_json else None,
                "lu": _parse_iso_to_dt(last_updated_at_iso),
            },
        )).first()
        await s.commit()

        if row is None:
            # ON CONFLICT path returned no row — shouldn't happen, but
            # if it does we fail-open to "claim" so we still drain.
            return {
                "thread_id": None, "claimed": True,
                "drain_cursor": None, "last_updated_at": None,
                "drain_failure_state": {},
                "last_drained_msg_count": 0,
            }

        thread_id = str(row.id)
        prior_drain_cursor = row.drain_cursor
        prior_last_updated_at = (
            row.last_updated_at.isoformat() if row.last_updated_at else None
        )
        prior_failure = row.drain_failure_state or {}
        last_drained_at = row.last_drained_at

        # Determine claim outcome.
        #
        #   1. Fresh row (inserted=True) or no prior drain  → claim. Always.
        #   2. Activity-aware override — Graph just told us this chat's
        #      lastUpdatedDateTime is strictly newer than what we drained
        #      against. Claim regardless of freshness window: an incremental
        #      re-drain (cursor-based) picks up only the new messages and is
        #      cheap. This is the durability guarantee — without it, a
        #      message that arrives mid-batch is invisible to every snapshot
        #      taken inside the freshness window.
        #   3. Stale last_drained_at (age > freshness window) → claim. Plain
        #      time-based re-drain.
        #   4. Otherwise → skip + reuse another backup's recently-drained
        #      messages.
        claimed: bool
        if row.inserted or last_drained_at is None:
            claimed = True
        else:
            prior_lu = row.prior_lu
            new_lu = row.last_updated_at  # what we just stamped in via UPSERT
            has_new_activity = bool(
                new_lu is not None
                and prior_lu is not None
                and new_lu > prior_lu
            )
            age_s = (datetime.utcnow().replace(tzinfo=None) -
                     last_drained_at.replace(tzinfo=None)).total_seconds()
            claimed = (
                has_new_activity
                or age_s > _CHAT_THREAD_DRAIN_FRESHNESS_S
            )

            # Plan P7 — skip-claim sanity check. If we're about to skip
            # (claimed=False), do one cheap MAX(created_date_time) check
            # against chat.lastUpdatedDateTime. A healthy drain leaves the
            # latest message timestamp roughly equal to the chat's. If
            # they diverge by more than ~24h, the prior drainer either
            # silently dropped pages (F6) or wrote corrupted timestamps —
            # we override the skip and force a fresh re-drain. Cheap to
            # run (~1 PG query per skip), catches integrity gaps inline
            # without waiting for the P4 nightly verifier.
            if not claimed and new_lu is not None:
                try:
                    _mx = (await s.execute(
                        text(
                            "SELECT MAX(created_date_time) AS mx "
                            "  FROM chat_thread_messages "
                            " WHERE chat_thread_id = :tid"
                        ),
                        {"tid": str(row.id)},
                    )).first()
                    _max_msg_ts = _mx.mx if _mx else None
                    if _max_msg_ts is not None:
                        _gap = (
                            new_lu.replace(tzinfo=None)
                            - _max_msg_ts.replace(tzinfo=None)
                        ).total_seconds()
                        if _gap > 86400:  # 24h tolerance
                            claimed = True
                            print(
                                f"[CHAT-CLAIM SANITY] chat_thread_id="
                                f"{row.id} gap={int(_gap)}s — overriding "
                                f"skip-claim, forcing re-drain"
                            )
                except Exception:
                    # Sanity check is best-effort. Don't fail the claim
                    # on a quirky PG hiccup; the worst case is we still
                    # skip and rely on P4 to catch it nightly.
                    pass
        return {
            "thread_id": thread_id,
            "claimed": claimed,
            "drain_cursor": prior_drain_cursor,
            "last_updated_at": prior_last_updated_at,
            "drain_failure_state": prior_failure if isinstance(prior_failure, dict) else {},
            "last_drained_msg_count": int(row.last_drained_msg_count or 0),
        }


async def _mark_chat_thread_drained(
    *,
    thread_id: str,
    drain_cursor: Optional[str],
    failure_state: Optional[Dict[str, Any]],
    msg_count: Optional[int] = None,
) -> None:
    """End-of-drain checkpoint. Bumps ``last_drained_at`` to NOW() and
    stores the new cursor + failure state.

    Argument semantics:
      * ``drain_cursor=None``     → leave drain_cursor untouched.
      * ``drain_cursor='2026…'``  → store as new cursor.
      * ``failure_state=None``    → leave drain_failure_state untouched.
      * ``failure_state={}``      → clear (success after a prior failure).
      * ``failure_state={...}``   → record this failure.
      * ``msg_count=None``        → leave last_drained_msg_count untouched.
      * ``msg_count=N``           → record persisted-message count after
                                    a successful drain. Used by the
                                    completeness gate on subsequent runs.
    """
    if not thread_id:
        return
    # Build the UPDATE dynamically so "leave untouched" really means
    # the column isn't in the SET clause — distinct from setting to NULL.
    set_parts = ["last_drained_at = NOW()", "updated_at = NOW()"]
    params: Dict[str, Any] = {"tid": thread_id}
    if drain_cursor is not None:
        set_parts.append("drain_cursor = :dc")
        params["dc"] = drain_cursor
    if failure_state is not None:
        set_parts.append("drain_failure_state = CAST(:fs AS JSONB)")
        params["fs"] = json.dumps(failure_state)
    if msg_count is not None:
        set_parts.append("last_drained_msg_count = :mc")
        params["mc"] = int(msg_count)
    # Plan P5 — this is the FINAL step in the drain chain and must
    # commit, because earlier steps (chat_thread_messages upsert,
    # snapshot_items pointer-write) already succeeded by the time we
    # get here. If we silently lose the cursor advance, the next
    # backup wastes work re-draining the same range; if we silently
    # lose the failure_state write, smart-skip never engages on a
    # known-broken chat. So: short retry with backoff before giving up.
    last_err: Optional[Exception] = None
    for _attempt in range(3):
        try:
            async with async_session_factory() as s:
                await s.execute(
                    text(
                        "UPDATE chat_threads SET " + ", ".join(set_parts) +
                        " WHERE id = :tid"
                    ),
                    params,
                )
                await s.commit()
                return
        except Exception as e:
            last_err = e
            if _attempt < 2:
                await asyncio.sleep(0.25 * (_attempt + 1))
                continue
    # All retries exhausted. Idempotency on chat_thread_messages still
    # makes re-drain safe; logged loudly so ops can investigate.
    logger.warning(
        "_mark_chat_thread_drained failed thread=%s after 3 retries: %s",
        thread_id, last_err,
    )


_CHAT_THREAD_MSG_BULK_CHUNK = 500


async def _bulk_upsert_chat_thread_messages(
    *,
    thread_id: str,
    msgs: List[Dict[str, Any]],
) -> int:
    """UPSERT into chat_thread_messages keyed by
    (chat_thread_id, message_external_id). Returns the number of rows
    attempted.

    ON CONFLICT DO UPDATE keeps lastModifiedDateTime / body fresh —
    re-drains of the same chat by a later backup pick up edits without
    needing to wipe the prior row.
    """
    if not msgs or not thread_id:
        return 0
    async with async_session_factory() as s:
        total = 0
        for i in range(0, len(msgs), _CHAT_THREAD_MSG_BULK_CHUNK):
            chunk = msgs[i:i + _CHAT_THREAD_MSG_BULK_CHUNK]
            rows = []
            for m in chunk:
                mid = m.get("id")
                if not mid:
                    continue
                body = (m.get("body") or {})
                frm = (m.get("from") or {}).get("user") or {}
                payload_bytes = _json_dumps_bytes(m)
                rows.append({
                    "tid": thread_id,
                    "ext": str(mid),
                    "cdt": _parse_iso_to_dt(m.get("createdDateTime")),
                    "ldt": _parse_iso_to_dt(m.get("lastModifiedDateTime")),
                    "fuid": (frm.get("id") or "")[:128],
                    "fdn": (frm.get("displayName") or "")[:256],
                    "bc": body.get("content"),
                    "bct": (body.get("contentType") or "")[:16] or None,
                    "ddt": _parse_iso_to_dt(m.get("deletedDateTime")),
                    "raw": json.dumps(m, default=str),
                    "ch": _fast_hash_hex(payload_bytes),
                    "sz": len(payload_bytes),
                })
            if not rows:
                continue
            # PG rejects ON CONFLICT DO UPDATE when the same conflict
            # target appears twice in a single statement
            # (CardinalityViolationError). Graph occasionally returns the
            # same message_external_id more than once inside one /messages
            # page (edits / system re-emits). Dedup by ext, last-wins so
            # the most-recent payload sticks.
            _seen: Dict[str, int] = {}
            for _i, _r in enumerate(rows):
                _seen[_r["ext"]] = _i
            rows = [rows[i] for i in _seen.values()]
            # Multi-row VALUES (...) statement.
            values_clause = ", ".join(
                f"(:tid_{i}, :ext_{i}, CAST(:cdt_{i} AS TIMESTAMPTZ), "
                f" CAST(:ldt_{i} AS TIMESTAMPTZ), :fuid_{i}, :fdn_{i}, "
                f" :bc_{i}, :bct_{i}, CAST(:ddt_{i} AS TIMESTAMPTZ), "
                f" CAST(:raw_{i} AS JSONB), :ch_{i}, :sz_{i})"
                for i in range(len(rows))
            )
            params: Dict[str, Any] = {}
            for i, r in enumerate(rows):
                for k, v in r.items():
                    params[f"{k}_{i}"] = v
            await s.execute(
                text(
                    "INSERT INTO chat_thread_messages "
                    "(chat_thread_id, message_external_id, created_date_time, "
                    " last_modified_date_time, from_user_id, from_display_name, "
                    " body_content, body_content_type, deleted_date_time, "
                    " metadata_raw, content_hash, content_size) "
                    f"VALUES {values_clause} "
                    "ON CONFLICT (chat_thread_id, message_external_id) DO UPDATE SET "
                    "  created_date_time       = EXCLUDED.created_date_time, "
                    "  last_modified_date_time = EXCLUDED.last_modified_date_time, "
                    "  from_user_id            = EXCLUDED.from_user_id, "
                    "  from_display_name       = EXCLUDED.from_display_name, "
                    "  body_content            = EXCLUDED.body_content, "
                    "  body_content_type       = EXCLUDED.body_content_type, "
                    "  deleted_date_time       = EXCLUDED.deleted_date_time, "
                    "  metadata_raw            = EXCLUDED.metadata_raw, "
                    "  content_hash            = EXCLUDED.content_hash, "
                    "  content_size            = EXCLUDED.content_size"
                ),
                params,
            )
            total += len(rows)
        await s.commit()
        return total


async def _load_chat_thread_messages_for_pointer(
    *,
    thread_id: str,
) -> List[Dict[str, Any]]:
    """Read minimal fields needed to emit thin snapshot_items pointer rows
    for a snapshot that did not drain this chat itself (claim lost or
    skipped-by-activity). Used by both the cross-user skip path and the
    drain-skip path."""
    if not thread_id:
        return []
    async with async_session_factory() as s:
        rows = (await s.execute(
            text(
                "SELECT message_external_id, body_content, content_size, content_hash "
                "  FROM chat_thread_messages "
                " WHERE chat_thread_id = :tid"
            ),
            {"tid": thread_id},
        )).all()
        return [
            {
                "external_id": r.message_external_id,
                "body_content": r.body_content,
                "content_size": r.content_size or 0,
                "content_hash": r.content_hash,
            }
            for r in rows
        ]


async def _carry_forward_prior_chat_snapshot_items(
    *,
    tenant_id: str,
    resource_id: str,
    target_snapshot_id: str,
) -> int:
    """Copy chat-related snapshot_items from this resource's immediate prior
    backup into the new snapshot.

    Why this exists: chat drain is incremental — each run pulls only NEW
    messages from Graph and writes only new pointer rows + freshly
    downloaded CHAT_ATTACHMENT / CHAT_HOSTED_CONTENT rows. Without
    carry-forward, the new snapshot would contain just the delta from this
    run, so snapshot.bytes_total (and the user-facing "Backup size")
    collapses on every incremental.

    The semantics we want: each chat snapshot IS the full point-in-time
    backup at completion time — a true superset of the prior snapshot
    plus newly-drained content. With that invariant restored:
      * Resource.storage_bytes (derived from latest snapshot's bytes_total)
        grows monotonically with incrementals
      * P8 cross-user backfill + this cross-time carry-forward together
        eliminate drain-order asymmetry: each user's snapshot stands on
        its own regardless of who drained first or when

    The actual blobs in SeaweedFS are tenant-deduped (one copy per
    content_hash), so carry-forward just re-emits the metadata pointer —
    no storage overhead in the object store. Per-snapshot row cost is
    ~200 bytes × items: negligible against the content.

    Called AFTER the drain + P8 cross-user backfill so any freshly drained
    rows in the new snapshot win the unique-key race. Carry-forward uses
    NOT EXISTS on (snapshot_id, external_id, item_type) so existing rows
    in the target are never overwritten.
    """
    if not tenant_id or not resource_id or not target_snapshot_id:
        return 0
    from sqlalchemy.exc import IntegrityError as _IntegrityError
    async with async_session_factory() as s:
        try:
            result = await s.execute(
                text(
                    "INSERT INTO snapshot_items ("
                    "  id, snapshot_id, tenant_id, item_type, external_id, "
                    "  parent_external_id, name, folder_path, content_hash, "
                    "  content_checksum, content_size, blob_path, "
                    "  encryption_key_id, backup_version, metadata, is_deleted, "
                    "  indexed_at, backend_id, created_at"
                    ") "
                    "SELECT gen_random_uuid(), :tsid, src.tenant_id, src.item_type, "
                    "       src.external_id, src.parent_external_id, src.name, "
                    "       src.folder_path, src.content_hash, src.content_checksum, "
                    "       src.content_size, src.blob_path, src.encryption_key_id, "
                    "       COALESCE(src.backup_version, 1), src.metadata, "
                    "       COALESCE(src.is_deleted, false), src.indexed_at, "
                    "       src.backend_id, NOW() "
                    "  FROM snapshot_items src "
                    "  JOIN snapshots ps ON ps.id = src.snapshot_id "
                    " WHERE ps.resource_id = :rid "
                    "   AND ps.id <> :tsid "
                    "   AND ps.status IN ('COMPLETED', 'PARTIAL') "
                    "   AND src.item_type IN ("
                    "         'CHAT_MESSAGE', 'CHAT_ATTACHMENT', 'CHAT_HOSTED_CONTENT'"
                    "       ) "
                    "   AND ps.id = ("
                    "         SELECT s2.id FROM snapshots s2 "
                    "          WHERE s2.resource_id = :rid "
                    "            AND s2.id <> :tsid "
                    "            AND s2.status IN ('COMPLETED', 'PARTIAL') "
                    "          ORDER BY s2.created_at DESC "
                    "          LIMIT 1"
                    "       ) "
                    "   AND NOT EXISTS ("
                    "         SELECT 1 FROM snapshot_items dst "
                    "          WHERE dst.snapshot_id = :tsid "
                    "            AND dst.external_id = src.external_id "
                    "            AND dst.item_type = src.item_type"
                    "       )"
                ),
                {
                    "tsid": target_snapshot_id,
                    "rid": resource_id,
                },
            )
        except _IntegrityError as e:
            # Target snapshot was deleted out from under us mid-carry-forward
            # (stale-snapshot GC / cancel-revert / a superseding concurrent
            # drain of the same resource). Mirror _bulk_upsert_snapshot_items:
            # surface the snapshot_items_snapshot_id_fkey violation as
            # SnapshotVanishedError so the caller aborts cleanly instead of
            # logging a raw ForeignKeyViolationError. No data loss — the prior
            # (source) snapshot still holds the full history; carrying rows
            # into a snapshot that no longer exists is a no-op by definition.
            # Match the FK constraint name, not message text, for robustness
            # across asyncpg / driver wording.
            if "snapshot_items_snapshot_id_fkey" in str(e):
                await s.rollback()
                raise SnapshotVanishedError(
                    f"snapshot {target_snapshot_id} no longer exists; "
                    f"aborting chat carry-forward"
                ) from e
            raise
        await s.commit()
        return result.rowcount or 0


class VersionListCoordinator:
    """Async coordinator that bunches per-file /versions requests into
    Graph $batch calls.

    Design:
      * Caller calls await coord.get_versions(file_id)
      * The call registers a Future and either:
          - triggers an immediate flush when pending >= batch_size, or
          - starts a deadline timer (max_wait_ms) that flushes on expiry
      * One $batch round-trip resolves up to batch_size waiters at once.
      * On per-sub-request failure (None from list_file_versions_batch),
        the coordinator falls back to a single-shot list_file_versions
        for that file so the caller never gets stuck.

    Why this exists: a single GET /versions costs ~150 ms of TCP/TLS/auth
    handshake. With 2,745 files × one per file = 7 min just on the list
    phase. Batched: 137 round trips × ~200 ms = 30 sec. Carry-forward
    further reduces the *number* of files that need listing; this
    coordinator makes the listing itself fast.

    Memory: bounded by batch_size pending Futures. No background tasks
    outlive a flush.
    """

    def __init__(
        self,
        graph_client,
        drive_id: str,
        batch_size: int = 20,
        max_wait_ms: int = 200,
    ):
        self._gc = graph_client
        self._drive_id = drive_id
        self._batch_size = max(1, min(batch_size, 20))
        self._max_wait_ms = max(50, max_wait_ms)
        self._pending: List[Tuple[str, "asyncio.Future"]] = []
        self._lock = asyncio.Lock()
        self._timer_task: Optional["asyncio.Task"] = None

    async def get_versions(self, file_id: str) -> List[Dict[str, Any]]:
        loop = asyncio.get_running_loop()
        fut: "asyncio.Future" = loop.create_future()
        flush_now: Optional[List[Tuple[str, "asyncio.Future"]]] = None
        async with self._lock:
            self._pending.append((file_id, fut))
            if len(self._pending) >= self._batch_size:
                flush_now = self._pending
                self._pending = []
                self._timer_task = None
            elif self._timer_task is None or self._timer_task.done():
                self._timer_task = asyncio.create_task(self._wait_and_flush())
        if flush_now is not None:
            asyncio.create_task(self._flush(flush_now))
        return await fut

    async def _wait_and_flush(self):
        try:
            await asyncio.sleep(self._max_wait_ms / 1000.0)
        except asyncio.CancelledError:
            return
        flush_now: Optional[List[Tuple[str, "asyncio.Future"]]] = None
        async with self._lock:
            if self._pending:
                flush_now = self._pending
                self._pending = []
                self._timer_task = None
        if flush_now is not None:
            asyncio.create_task(self._flush(flush_now))

    async def _flush(self, batch: List[Tuple[str, "asyncio.Future"]]):
        file_ids = [fid for fid, _ in batch]
        try:
            results = await self._gc.list_file_versions_batch(self._drive_id, file_ids)
        except Exception as e:
            # Whole batch blew up — fall every waiter back to a single-shot
            # call so we never deadlock a backup on a batched failure.
            for fid, fut in batch:
                if fut.done():
                    continue
                try:
                    versions = await self._gc.list_file_versions(self._drive_id, fid)
                    fut.set_result(versions)
                except Exception as e2:
                    fut.set_exception(e2)
            return
        # Resolve per-file; fall back to single-shot for any None (batch
        # retry budget exhausted for that sub-request).
        for fid, fut in batch:
            if fut.done():
                continue
            versions = results.get(fid)
            if versions is None:
                try:
                    versions = await self._gc.list_file_versions(self._drive_id, fid)
                except Exception as e3:
                    fut.set_exception(e3)
                    continue
            fut.set_result(versions or [])


async def _fetch_prior_file_etag_map(
    *,
    resource_id: str,
    current_snapshot_id: str,
    file_ids: List[str],
) -> Tuple[Optional[str], Dict[str, str], Dict[str, set]]:
    """Look up the immediate prior COMPLETED snapshot for this resource and
    return:

    - prior_snap_id (str or None)
    - prior_etag_by_file: {file_id → source_etag} from that snapshot's FILE rows
    - captured_versions_by_file: {file_id → {version_id, ...}} from that snapshot's
      FILE_VERSION rows. Pulled from metadata->>'version_id' since that's the
      stable cross-version identity.

    Why a single helper: lets the caller compute everything in TWO indexed
    queries per resource (not per file), then make per-file carry-forward
    decisions in pure Python with no further DB round-trips.
    """
    if not (resource_id and current_snapshot_id and file_ids):
        return None, {}, {}
    async with async_session_factory() as s:
        prior_row = (await s.execute(
            text(
                "SELECT id FROM snapshots "
                " WHERE resource_id = :rid AND id <> :csid "
                "   AND status IN ('COMPLETED', 'PARTIAL') "
                " ORDER BY created_at DESC LIMIT 1"
            ),
            {"rid": resource_id, "csid": current_snapshot_id},
        )).first()
        if prior_row is None:
            return None, {}, {}
        prior_snap_id = str(prior_row[0])

        # Pull both FILE and FILE_VERSION rows in one query (still narrowly
        # filtered by snapshot_id + file_id set so the planner uses the
        # snapshot_id index then a small index scan).
        # FILE rows store etag at metadata->'structured'->>'source_etag'
        # (see _create_file_snapshot_item — wraps the SharePoint metadata
        # under a 'structured' key). FILE_VERSION rows we write at
        # _backup_file_versions store version_id at the top level of
        # metadata. COALESCE both paths so the query works for either layout.
        rows = (await s.execute(
            text(
                "SELECT external_id, item_type, parent_external_id, "
                "       COALESCE("
                "         metadata->'structured'->>'source_etag', "
                "         metadata->>'source_etag'"
                "       ) AS file_etag, "
                "       metadata->>'version_id' AS version_id "
                "  FROM snapshot_items "
                " WHERE snapshot_id = :sid "
                "   AND ( "
                "         (item_type = 'FILE'         AND external_id = ANY(:fids)) "
                "      OR (item_type = 'FILE_VERSION' AND parent_external_id = ANY(:fids)) "
                "       )"
            ),
            {"sid": prior_snap_id, "fids": file_ids},
        )).all()
    prior_etag_by_file: Dict[str, str] = {}
    captured_versions_by_file: Dict[str, set] = {}
    for ext_id, item_type, parent_ext, file_etag, version_id in rows:
        if item_type == "FILE":
            if file_etag:
                prior_etag_by_file[ext_id] = file_etag
        elif item_type == "FILE_VERSION":
            if parent_ext and version_id:
                captured_versions_by_file.setdefault(parent_ext, set()).add(version_id)
    return prior_snap_id, prior_etag_by_file, captured_versions_by_file


async def _carry_forward_prior_file_versions(
    *,
    target_snapshot_id: str,
    prior_snap_id: str,
    file_ids: List[str],
) -> int:
    """Bulk-clone FILE_VERSION rows for the given file_ids from prior snapshot
    into the target. Returns rows-copied count.

    Triggered when the current FILE's eTag matches the prior snapshot's FILE
    eTag — proving the file is byte-identical, so its version chain is
    necessarily identical too. No Graph calls, no downloads — pure SQL row
    duplication pointing at the existing (tenant-deduped) Seaweed blobs.

    Idempotent via NOT EXISTS on (snapshot_id, external_id, item_type) — safe
    to call multiple times within the same snapshot run.

    Indexing assumption: parent_external_id is populated on FILE_VERSION rows
    going forward. Rows from before that change have parent_external_id=NULL
    and won't be cloned by this query — those resources fall through to the
    normal re-capture path on the first post-deploy backup, then carry-forward
    naturally from the second backup onward.
    """
    if not (target_snapshot_id and prior_snap_id and file_ids):
        return 0
    async with async_session_factory() as s:
        result = await s.execute(
            text(
                "INSERT INTO snapshot_items ("
                "  id, snapshot_id, tenant_id, item_type, external_id, "
                "  parent_external_id, name, folder_path, content_hash, "
                "  content_checksum, content_size, blob_path, "
                "  encryption_key_id, backup_version, metadata, is_deleted, "
                "  indexed_at, backend_id, created_at"
                ") "
                "SELECT gen_random_uuid(), :tsid, src.tenant_id, src.item_type, "
                "       src.external_id, src.parent_external_id, src.name, "
                "       src.folder_path, src.content_hash, src.content_checksum, "
                "       src.content_size, src.blob_path, src.encryption_key_id, "
                "       COALESCE(src.backup_version, 1), src.metadata, "
                "       COALESCE(src.is_deleted, false), src.indexed_at, "
                "       src.backend_id, NOW() "
                "  FROM snapshot_items src "
                " WHERE src.snapshot_id = :psid "
                "   AND src.item_type = 'FILE_VERSION' "
                "   AND src.parent_external_id = ANY(:fids) "
                "   AND NOT EXISTS ("
                "         SELECT 1 FROM snapshot_items dst "
                "          WHERE dst.snapshot_id = :tsid "
                "            AND dst.external_id = src.external_id "
                "            AND dst.item_type = src.item_type"
                "       )"
            ),
            {"tsid": target_snapshot_id, "psid": prior_snap_id, "fids": file_ids},
        )
        await s.commit()
        return result.rowcount or 0


async def _copy_chat_attachment_rows_to_snapshot(
    *,
    tenant_id: str,
    target_snapshot_id: str,
    chat_id: str,
) -> int:
    """Per-snapshot CHAT_ATTACHMENT / CHAT_HOSTED_CONTENT pointer rows for
    claim-skipped users (plan P8).

    Today, attachment rows are only persisted in the FIRST drainer's
    snapshot. Akshat's skip-claim path writes message pointer rows but no
    attachment rows -- so Akshat's UI would show attachment chips via the
    tenant-wide /attachments fallback (snapshot-service:2273), but if
    Amit's snapshot is later deleted (retention, GDPR, account
    deactivation), Akshat loses the chips entirely.

    Fix: INSERT ... SELECT from any existing tenant CHAT_ATTACHMENT /
    CHAT_HOSTED_CONTENT row whose parent_external_id is a message in this
    chat thread, with new id + target snapshot_id. The blob_path is
    reused (same SeaweedFS blob, no upload). Idempotent via WHERE NOT
    EXISTS on (target_snapshot_id, external_id, item_type).

    Returns the number of rows actually inserted.
    """
    if not tenant_id or not target_snapshot_id or not chat_id:
        return 0
    async with async_session_factory() as s:
        # Race-free idempotent copy: rely on the (snapshot_id, external_id,
        # item_type) unique index via ON CONFLICT DO NOTHING. Two shards
        # claiming different chats on the same partitioned snapshot may
        # both reference the same source attachment (e.g. an attachment
        # forwarded between chats); the old NOT EXISTS subquery raced
        # because it evaluated at SELECT time while the unique constraint
        # fires at INSERT time. DISTINCT ON also collapses any intra-call
        # duplicates the source SELECT itself produces (one source row per
        # snapshot it's been kept in, but only one destination row needed).
        result = await s.execute(
            text(
                "INSERT INTO snapshot_items ("
                "  id, snapshot_id, tenant_id, item_type, external_id, "
                "  parent_external_id, name, folder_path, content_hash, "
                "  content_checksum, content_size, blob_path, "
                "  encryption_key_id, backup_version, metadata, is_deleted, "
                "  indexed_at, backend_id, created_at"
                ") "
                "SELECT DISTINCT ON (src.external_id, src.item_type) "
                "       gen_random_uuid(), :tsid, :tid, src.item_type, "
                "       src.external_id, "
                "       COALESCE(src.parent_external_id, split_part(src.external_id, '::', 1)), "
                "       src.name, "
                "       src.folder_path, src.content_hash, "
                "       src.content_checksum, src.content_size, "
                "       src.blob_path, src.encryption_key_id, "
                "       COALESCE(src.backup_version, 1), src.metadata, "
                "       COALESCE(src.is_deleted, false), src.indexed_at, "
                "       src.backend_id, NOW() "
                "  FROM snapshot_items src "
                " WHERE src.tenant_id = :tid "
                "   AND src.item_type IN ('CHAT_ATTACHMENT', 'CHAT_HOSTED_CONTENT') "
                "   AND COALESCE(src.parent_external_id, split_part(src.external_id, '::', 1)) IN ( "
                "         SELECT m.message_external_id "
                "           FROM chat_thread_messages m "
                "           JOIN chat_threads t ON t.id = m.chat_thread_id "
                "          WHERE t.tenant_id = :tid AND t.chat_id = :cid "
                "       ) "
                "ON CONFLICT (snapshot_id, external_id, item_type) DO NOTHING"
            ),
            {
                "tsid": target_snapshot_id,
                "tid": tenant_id,
                "cid": chat_id,
            },
        )
        await s.commit()
        return result.rowcount or 0


async def _is_job_cancelled(job_id) -> bool:
    """Cheap best-effort cancel-check. Long-running handlers poll this at
    heartbeat boundaries so a DB-level CANCELLED job stops pulling Graph
    pages within seconds instead of running to natural completion. A DB
    hiccup returns False (don't cancel on transient errors)."""
    if job_id is None:
        return False
    try:
        if isinstance(job_id, str):
            job_id = uuid.UUID(job_id)
    except Exception:
        return False
    try:
        from shared.database import async_session_factory as _f
        from shared.models import Job as _J
        async with _f() as _s:
            _j = await _s.get(_J, job_id)
            if not _j:
                return False
            status_val = _j.status.name if hasattr(_j.status, "name") else str(_j.status)
            return status_val == "CANCELLED"
    except Exception:
        return False


class JobCancelledMidFlight(Exception):
    """Raised from the per-resource backup loop when the DB job row flips
    to CANCELLED. Propagates through upload_stream (which already aborts
    any in-flight multipart in its except block), so orphan part bytes are
    released on the backend. Already-uploaded singlepart blobs are reaped
    by cancel_job's `_revert_snapshot_storage` — cancel is a full revert,
    not a soft-close, which keeps ghost bytes out of SeaweedFS / Azure."""


async def _raise_if_job_cancelled(job_id) -> None:
    """Call between resources (and optionally between large item batches)
    so a user cancel becomes effective within one resource instead of one
    whole batch. Transient DB errors never cancel — only a confirmed
    CANCELLED status does."""
    if await _is_job_cancelled(job_id):
        raise JobCancelledMidFlight(f"job {job_id} cancelled mid-flight")


async def _coerce_snapshot_terminal_on_cancel(snapshot, proposed_status):
    """When parent job is CANCELLED, downgrade a would-be terminal snapshot
    status to FAILED so the cancelled work is excluded from delta-from-prior
    and the UI shows ✗ instead of ✓.

    Without this guard, a job that gets cancelled AFTER its snapshot already
    walked the data ends up:
      * job.status = CANCELLED (set by cancel_job)
      * snapshot.status = COMPLETED (set here, blind to the cancel)

    The next incremental then anchors delta math against this "complete"
    cancelled snapshot — producing the ghost-prior pattern seen on
    2026-05-17 (Gajraj USER_CHATS: ghost @18:59:06 + real @18:59:44 anchored
    on it for 4685-items / 80 MB bogus bytes_added). The duplicate-trigger
    root cause (two batches in 43s) is upstream; this guard is the defensive
    correction at finalize time so racing cancel + completion is consistent
    regardless of upstream dedup.
    """
    job_id = getattr(snapshot, "job_id", None)
    if not job_id or not await _is_job_cancelled(job_id):
        return proposed_status
    try:
        ed = dict(snapshot.extra_data or {})
        ed["finalize_cancelled"] = True
        ed["finalize_cancelled_at"] = datetime.utcnow().isoformat()
        ed["original_proposed_status"] = (
            proposed_status.name if hasattr(proposed_status, "name")
            else str(proposed_status)
        )
        snapshot.extra_data = ed
    except Exception:
        pass
    return SnapshotStatus.FAILED


async def _update_job_pct(job_id, pct: int) -> None:
    """Write live `jobs.progress_pct` on a short-lived session.

    LEGACY: the authoritative progress is now derived at read time in
    job-service (``_job_rollup_bulk``) from the snapshots table, so this
    column write is **best-effort cosmetic only** — UI never reads it for
    RUNNING jobs (see services/job-service/main.py:_project_job_progress).
    Kept so terminal states and a coarse "X% of resource-groups done"
    signal remain available to anyone querying the column directly
    (Grafana, ad-hoc DB inspection). At 5K-user scale this write can
    contend with the rollup query; if that becomes hot, delete the call
    sites — UI correctness no longer depends on them."""
    if job_id is None:
        return
    try:
        if isinstance(job_id, str):
            job_id = uuid.UUID(job_id)
    except Exception:
        return
    clamped = max(0, min(100, int(pct)))
    try:
        from shared.database import async_session_factory as _f
        from shared.models import Job as _J
        async with _f() as _s:
            _j = await _s.get(_J, job_id)
            if not _j:
                return
            status_val = _j.status.name if hasattr(_j.status, "name") else str(_j.status)
            if status_val not in ("RUNNING", "QUEUED"):
                return
            _j.progress_pct = clamped
            await _s.commit()
    except Exception:
        pass
