logger = logging.getLogger(__name__)


class _CachedAttachmentResult:
    """Return type of ``_fetch_url_deduped``.

    Two flavors:

      * **Cache miss (fresh fetch)** — ``bytes_`` is the downloaded payload;
        every other field is ``None``. The caller hashes the bytes and runs
        them through the inline-or-blob upload path as before.

      * **Cache hit** — ``bytes_`` is ``None`` and ``content_hash`` is set;
        either ``blob_path`` (large content already in storage) or
        ``inline_b64`` (small content kept inline) carries the payload
        descriptor. The caller skips hash + upload entirely and stamps the
        SnapshotItem with the cached descriptor — saving the Graph
        ``/shares`` resolve, the CDN download, and the storage write.

    ``unreachable=True`` mirrors a permanent 4xx from a prior backup so
    later backups don't re-try the broken URL.
    """
    __slots__ = ("bytes_", "content_hash", "blob_path", "inline_b64",
                 "content_size", "unreachable")

    def __init__(
        self,
        bytes_: Optional[bytes] = None,
        content_hash: Optional[str] = None,
        blob_path: Optional[str] = None,
        inline_b64: Optional[str] = None,
        content_size: int = 0,
        unreachable: bool = False,
    ) -> None:
        self.bytes_ = bytes_
        self.content_hash = content_hash
        self.blob_path = blob_path
        self.inline_b64 = inline_b64
        self.content_size = content_size
        self.unreachable = unreachable

    @property
    def is_cache_hit(self) -> bool:
        return self.bytes_ is None and (
            self.blob_path is not None or self.inline_b64 is not None
        )


class _ChatAttDedup:
    """Snapshot-wide dedup state for chat-attachment capture.

    Without this, every per-chat ``_userchats_backup_attachments`` call
    builds its own URL / driveItem / content-hash caches. A screenshot
    referenced in six chats is therefore resolved 6×, downloaded 6×, and
    hashed 6× before content-hash dedup finally collapses the upload.
    Sharing one instance across every per-chat kick within one USER_CHATS
    run cuts the redundant Graph round-trips and CDN egress.

    ``tenant_url_cache_*`` track the persisted (cross-snapshot, cross-user)
    URL cache layered on top — see ``chat_url_cache`` in shared/models.py.

    Memory note: ``url_cache`` retains resolved bytes for as long as ANY
    chat still references that URL. Bounded by ``unique_urls × avg_size``
    — empirically ~300 unique URLs × ~2 MB ≈ 600 MB peak on a fat
    tenant, which is well inside the backup-worker container budget.

    Must be instantiated from an async context (locks pin to the
    current event loop on first use).
    """
    __slots__ = (
        "url_cache", "url_tasks",
        "driveitem_tasks", "driveitem_lock", "di_dedup_hits",
        "hash_upload_tasks", "hash_upload_lock", "hash_stats",
        "tenant_url_cache_stats",
    )

    def __init__(self) -> None:
        self.url_cache: Dict[str, "_CachedAttachmentResult"] = {}
        self.url_tasks: Dict[str, "asyncio.Task[_CachedAttachmentResult]"] = {}
        self.driveitem_tasks: Dict[str, "asyncio.Future[Optional[bytes]]"] = {}
        self.driveitem_lock = asyncio.Lock()
        self.di_dedup_hits: Dict[str, int] = {"n": 0}
        self.hash_upload_tasks: Dict[str, "asyncio.Future[Optional[str]]"] = {}
        self.hash_upload_lock = asyncio.Lock()
        self.hash_stats: Dict[str, int] = {
            "in_phase_hits": 0, "db_hits": 0, "uploads": 0,
        }
        # Counters for the persisted chat_url_cache layer:
        #   hits             — cached URL re-used (skipped resolve + download)
        #   unreachable_skip — cached URL was known-broken; skipped silently
        #   miss_writes      — fresh fetch that wrote a new cache row
        self.tenant_url_cache_stats: Dict[str, int] = {
            "hits": 0, "unreachable_skip": 0, "miss_writes": 0,
        }


def _classify_chat_drain_error(status: Optional[int], exc: Exception) -> str:
    """Map a chat-drain failure to a category that decides whether the next
    backup retries this chat or skips it.

      PERMISSION (403)  — Graph said "your app can't read this resource".
                          Stable until an admin grants new scopes; record the
                          app's current scope fingerprint and skip until it
                          changes.
      GONE (404)        — Resource no longer exists. Skip until it reappears
                          in the chat list.
      THROTTLE (429)    — Rate limited; retry next backup (Graph budget will
                          have refilled by then). Never skip.
      AUTH (401)        — Token expired / invalidated; same as transient at
                          the chat layer — _iter_pages handles token refresh
                          internally, so 401 reaching here is unusual.
      TRANSIENT         — 5xx, network errors, anything else. Always retry.
    """
    if status == 403:
        return "PERMISSION"
    if status == 404:
        return "GONE"
    if status == 429:
        return "THROTTLE"
    if status == 401:
        return "AUTH"
    return "TRANSIENT"


def _message_to_contact_shape(msg: dict) -> dict:
    """Best-effort: convert an IPM.Contact message (from Deleted Items or
    Recoverable Items folders) into a dict that looks like a Graph contact
    resource. Field recovery is lossy by nature — deleted contacts lose
    most structured fields when they enter the message store. We preserve
    the original id, fall back to subject for displayName, and extract
    any emails we can find from the 'from' field."""
    if not isinstance(msg, dict):
        msg = {}
    display = msg.get("subject") or "(deleted contact)"
    emails: list = []

    from_field = msg.get("from") or {}
    addr = (from_field.get("emailAddress") or {}).get("address")
    if addr:
        emails.append({
            "address": addr,
            "name": (from_field.get("emailAddress") or {}).get("name") or display,
        })

    shape = {
        "id": msg.get("id"),
        "displayName": display,
        "givenName": "",
        "surname": "",
        "companyName": "",
        "jobTitle": "",
        "emailAddresses": emails,
        "businessPhones": [],
        "mobilePhone": "",
        "homePhones": [],
        "imAddresses": [],
        "categories": msg.get("categories") or [],
        "personalNotes": msg.get("bodyPreview") or "",
        "birthday": "",
    }
    if "singleValueExtendedProperties" in msg:
        shape["singleValueExtendedProperties"] = msg["singleValueExtendedProperties"]
    return shape


async def _backup_contacts_for_user(
    graph_client, user_id: str, item_limit: int = 999,
    prior_deltas: Optional[Dict[str, str]] = None,
):
    """Aggregate a user's contacts from /contactFolders + (optionally)
    Deleted Items + Recoverable Items folders.

    Delta semantics (fix for "contacts re-fetched every backup"):
      * ``prior_deltas`` is a dict ``{source_key -> deltaLink_url}`` from
        the previous backup. ``source_key`` is ``"__root__"`` for the
        top-level /users/{uid}/contacts/delta stream, or a folder id
        for /contactFolders/{fid}/contacts/delta.
      * On a fresh user (no prior_deltas) we walk the delta endpoint
        from scratch — Graph returns the full contact list followed
        by an ``@odata.deltaLink`` on the terminal page. We persist
        that link so subsequent runs only fetch CHANGED contacts.
      * On incremental runs we use the saved deltaLink directly as
        ``next_url``; Graph treats it as "give me changes since X."
      * Deleted contacts come back as ``{"@removed": {"reason":...}}``
        objects with just an ``id`` field — we surface those to the
        caller too so it can mark snapshot_items deleted.

    Returns ``(row_tuples, new_deltas)``:
      * ``row_tuples`` — list of
        ``(item_type, name, external_id, payload_dict, folder_name)``.
      * ``new_deltas`` — fresh ``{source_key -> deltaLink}`` to persist
        in ``resource.extra_data['contacts_deltas']`` for the next run.
    """
    from shared.config import settings

    select_fields = (
        "id,displayName,givenName,surname,companyName,jobTitle,emailAddresses,"
        "businessPhones,mobilePhone,homePhones,parentFolderId,categories,"
        "imAddresses,personalNotes,birthday"
    )

    prior_deltas = prior_deltas or {}
    new_deltas: Dict[str, str] = {}

    folder_map: dict = {}
    folder_ids: list = []
    try:
        f_page = await graph_client._get(
            f"{graph_client.GRAPH_URL}/users/{user_id}/contactFolders",
            params={"$top": "100", "$select": "id,displayName"},
        )
        for f in (f_page or {}).get("value", []) or []:
            fid = f.get("id")
            if fid:
                folder_map[fid] = f.get("displayName") or ""
                folder_ids.append(fid)
    except Exception:
        pass

    async def _fetch_contacts(url):
        """Plain (non-delta) page walk — preserved for the Deleted-
        Items and Recoverable-Items folders below which don't have a
        delta endpoint."""
        all_rows = []
        next_url = url
        params = {"$top": str(item_limit), "$select": select_fields}
        pages = 0
        while next_url and pages < 50:
            try:
                page_data = await graph_client._get(next_url, params=params)
            except Exception as exc:
                logger.warning("Contact fetch failed on %s: %s", next_url, exc)
                break
            all_rows.extend(page_data.get("value", []) or [])
            next_url = page_data.get("@odata.nextLink")
            params = None
            pages += 1
        return all_rows

    async def _fetch_contacts_delta(source_key: str, initial_url: str):
        """Walk the /contacts/delta endpoint and capture the terminal
        ``@odata.deltaLink`` into ``new_deltas[source_key]``. Resumes
        from ``prior_deltas[source_key]`` when present — Graph returns
        ONLY changes since that token, including ``@removed`` tombstones.

        Returns the list of value rows (changed contacts + tombstones)."""
        all_rows: List[Dict[str, Any]] = []
        prior = prior_deltas.get(source_key)
        if prior:
            # Resume — pass the saved deltaLink verbatim. It encodes
            # its own $deltatoken so we drop our own params.
            next_url = prior
            params = None
        else:
            next_url = initial_url
            params = {"$top": str(item_limit), "$select": select_fields}
        pages = 0
        while next_url and pages < 100:
            try:
                page_data = await graph_client._get(next_url, params=params)
            except Exception as exc:
                logger.warning(
                    "Contact delta fetch failed on %s: %s",
                    next_url[:120], exc,
                )
                # On error we deliberately DO NOT update new_deltas[key]
                # — the caller will fall back to prior_deltas (or full
                # fetch on next run if there was none), which is the
                # correct durability guarantee.
                return all_rows
            all_rows.extend(page_data.get("value", []) or [])
            params = None
            # @odata.nextLink continues paging; @odata.deltaLink marks
            # the terminal page and gives us the cursor for next time.
            nlink = page_data.get("@odata.nextLink")
            dlink = page_data.get("@odata.deltaLink")
            if dlink:
                new_deltas[source_key] = dlink
                next_url = None
            else:
                next_url = nlink
            pages += 1
        return all_rows

    async def _fetch_messages(url):
        all_rows = []
        next_url = url
        pages = 0
        while next_url and pages < 50:
            try:
                page_data = await graph_client._get(next_url)
            except Exception as exc:
                logger.warning("Deleted-contact fetch failed on %s: %s", next_url, exc)
                break
            all_rows.extend(page_data.get("value", []) or [])
            next_url = page_data.get("@odata.nextLink")
            pages += 1
        return all_rows

    aggregated: dict = {}
    folder_override: dict = {}
    tombstone_ids: List[str] = []

    def _ingest_delta_row(c: Dict[str, Any]) -> None:
        """Apply one row from a /contacts/delta page to ``aggregated``.

        Graph delta encodes deletes as ``{"@removed": {...}, "id": "..."}``
        rather than returning a normal contact. We collect those ids
        into ``tombstone_ids`` so the caller can surface them as
        deletion events (snapshot_items.deleted_at marking happens at
        the upsert layer downstream)."""
        cid = c.get("id")
        if not cid:
            return
        if c.get("@removed"):
            tombstone_ids.append(cid)
            return
        if cid not in aggregated:
            aggregated[cid] = c

    # Top-level /contacts/delta — covers contacts not nested in a custom
    # folder. On first run returns everything + a deltaLink; subsequent
    # runs return only changes since the last cursor.
    root_url = f"{graph_client.GRAPH_URL}/users/{user_id}/contacts/delta"
    for c in await _fetch_contacts_delta("__root__", root_url):
        _ingest_delta_row(c)
    # Per-folder /contactFolders/{fid}/contacts/delta — same shape,
    # one cursor per folder so adding/removing a folder doesn't reset
    # the others.
    for fid in folder_ids:
        f_url = (
            f"{graph_client.GRAPH_URL}/users/{user_id}"
            f"/contactFolders/{fid}/contacts/delta"
        )
        for c in await _fetch_contacts_delta(fid, f_url):
            _ingest_delta_row(c)

    # itemClass isn't a native property of microsoft.graph.message, so
    # filtering by it returns 400. Contact items live in mail folders with
    # the MAPI property PidTagMessageClass (id 0x001A) set to "IPM.Contact",
    # which Graph surfaces as a singleValueExtendedProperty. Filter on that
    # and $expand the same property so ``_message_to_contact_shape`` can
    # read the class back on each hit.
    MSG_CLASS_EP = "String 0x001A"
    contact_class_filter = (
        f"singleValueExtendedProperties/Any(ep:"
        f" ep/id eq '{MSG_CLASS_EP}'"
        f" and startswith(ep/value,'IPM.Contact'))"
    )
    from urllib.parse import quote as _q
    contact_class_expand = (
        f"singleValueExtendedProperties($filter=id eq '{MSG_CLASS_EP}')"
    )

    if settings.BACKUP_CONTACTS_INCLUDE_DELETED:
        del_url = (
            f"{graph_client.GRAPH_URL}/users/{user_id}"
            f"/mailFolders('deleteditems')/messages"
            f"?$filter={_q(contact_class_filter)}"
            f"&$expand={_q(contact_class_expand)}"
            f"&$top={item_limit}"
        )
        for msg in await _fetch_messages(del_url):
            shape = _message_to_contact_shape(msg)
            cid = shape.get("id")
            if cid and cid not in aggregated:
                aggregated[cid] = shape
                folder_override[cid] = "Deleted Items"

    if settings.BACKUP_CONTACTS_INCLUDE_RECOVERABLE:
        rec_url = (
            f"{graph_client.GRAPH_URL}/users/{user_id}"
            f"/mailFolders('recoverableitemsdeletions')/messages"
            f"?$filter={_q(contact_class_filter)}"
            f"&$expand={_q(contact_class_expand)}"
            f"&$top={item_limit}"
        )
        for msg in await _fetch_messages(rec_url):
            shape = _message_to_contact_shape(msg)
            cid = shape.get("id")
            if cid and cid not in aggregated:
                aggregated[cid] = shape
                folder_override[cid] = "Recoverable Items"

    out_rows = []
    for cid, c in aggregated.items():
        folder_name = (
            folder_override.get(cid)
            or folder_map.get(c.get("parentFolderId"))
            or "Contacts"
        )
        name = (
            c.get("displayName")
            or (c.get("emailAddresses") or [{}])[0].get("address")
            or "(unnamed)"
        )
        out_rows.append(("USER_CONTACT", name, cid, {"raw": c}, folder_name))
    # Tombstones — surface as DELETED rows so the snapshot_items diff
    # layer can mark them removed. payload carries the bare id so the
    # downstream upsert path can locate the existing row.
    for tid in tombstone_ids:
        out_rows.append((
            "USER_CONTACT", "(deleted)", tid,
            {"raw": {"id": tid, "@removed": True}},
            "Contacts",
        ))
    return out_rows, new_deltas


class AuditLogger:
    """Logs backup events via HTTP POST to audit-service.

    Single path — HTTP only. The previous implementation also published
    to the `audit.events` RabbitMQ queue, and audit-service's
    consume_audit_events() consumer wrote the same payload into
    audit_events a second time. That caused exact duplicate rows for
    every BACKUP / RANSOMWARE_SIGNAL log (4 RANSOMWARE_SIGNAL rows for
    2 alerts in the 2026-05-15 Hemant Singh false-positive case).
    Other workers (discovery-worker, chat-export-worker,
    azure-workload-worker, restore-worker, shared/audit.py) all use
    HTTP only — this aligns backup-worker with that convention.
    """

    def __init__(self):
        self.audit_url = f"{settings.AUDIT_SERVICE_URL}/api/v1/audit/log"

    async def log(self, **kwargs):
        try:
            async with httpx.AsyncClient(timeout=5.0) as client:
                await client.post(self.audit_url, json=kwargs)
        except Exception as e:
            print(f"[AuditLogger] HTTP failed: {e}")


class BackupWorker:
    """High-performance backup worker with parallelism and Server-Side Copy"""

    def __init__(self):
        self.worker_id = f"worker-{uuid.uuid4().hex[:8]}"
        self.graph_clients: Dict[str, GraphClient] = {}
        self.audit_logger = AuditLogger()
        # Teams chat export cache: user_id -> (fetched_at_unix, messages[], delta_link)
        # /users/{id}/chats/getAllMessages/delta returns either the full chat
        # history (first run) or only changes since the saved deltaLink.
        # If we're backing up 100 chats for the same user we don't want to hit
        # that endpoint 100 times. Cache TTL is 5 min — well within a batch-backup
        # window, and new messages arriving during a run are handled on the next run.
        # delta_link is captured so callers can persist it per-resource for the
        # next backup run to use as an incremental anchor.
        self._chat_export_cache: Dict[str, Tuple[float, List[Dict], Optional[str]]] = {}
        self._chat_export_cache_ttl = 300.0  # seconds
        # Concurrency controls
        self.backup_semaphore = asyncio.Semaphore(8)  # 8 concurrent file streams per worker NIC
        self.copy_semaphore = asyncio.Semaphore(20)  # Azure Storage account ingress limit
        # v2: cap simultaneous USER_ONEDRIVE backup jobs per worker. An uncapped
        # run can take hours; without this a single worker would accept every
        # redelivered OneDrive message and thrash. Heavy-pool workers
        # (backup-worker-heavy) set MAX_CONCURRENT_ONEDRIVE_BACKUPS_PER_WORKER
        # to 1 so they finish one monster drive before touching the next.
        self._onedrive_backup_semaphore = asyncio.Semaphore(
            settings.MAX_CONCURRENT_ONEDRIVE_BACKUPS_PER_WORKER
        )
        # Per-tenant fairness across partitions. Without this a tenant
        # whose drive split into 4 shards can grab every partition slot
        # on a replica, leaving sibling tenants' shards waiting in the
        # queue. Lazily allocated; one Semaphore per tenant_id.
        self._tenant_backup_semaphores: Dict[str, asyncio.Semaphore] = {}
        self._tenant_sem_lock = asyncio.Lock()
        # Which normal-priority queue this instance consumes. Default
        # replicas read backup.normal; backup-worker-heavy sets
        # BACKUP_WORKER_QUEUE=backup.heavy via compose env.
        self._backup_queue_name = settings.BACKUP_WORKER_QUEUE
        # Worker region stamp — observability for multi-region setups.
        # Defaults to "default" for single-region deployments so the
        # column never goes NULL.
        self._worker_region = os.getenv("WORKER_REGION", "default")

    async def initialize(self):
        await message_bus.connect()
        if azure_storage_manager.shards:
            print(f"[{self.worker_id}] Azure Storage: {len(azure_storage_manager.shards)} shard(s) ready")
        print(f"[{self.worker_id}] Backup worker initialized (concurrency={settings.BACKUP_CONCURRENCY})")
        # Liveness heartbeat for the reconciliation sweeper. UPSERTs
        # worker_heartbeats every 10 s; tombstoned on shutdown so the
        # sweeper picks up any in-flight work immediately rather than
        # waiting the full 60 s staleness window.
        try:
            from shared.heartbeat import HeartbeatThread
            self._heartbeat = HeartbeatThread(
                worker_id=self.worker_id,
                service_name=os.getenv("RAILWAY_SERVICE_NAME", "backup_worker"),
                queues=[self._backup_queue_name],
            )
            await self._heartbeat.start()
        except Exception as exc:
            self._heartbeat = None
            print(f"[{self.worker_id}] heartbeat init failed (continuing): {exc}")
        # LeaseExtender — one background task per worker that bumps
        # lease_expires_at on every row this worker currently holds.
        # Defense against the worker getting stuck on a long-running
        # task that exceeds LEASE_TTL_S, which would cause the
        # reconciler to mistake us for dead and steal our work.
        try:
            from shared.lease import LeaseExtender
            if self._heartbeat is not None:
                self._lease_extender = LeaseExtender(
                    owner_id=self._heartbeat.worker_uuid,
                    session_factory=async_session_factory,
                )
                await self._lease_extender.start()
            else:
                self._lease_extender = None
        except Exception as exc:
            self._lease_extender = None
            print(f"[{self.worker_id}] lease extender init failed (continuing): {exc}")
        # Startup reclaim — re-publish any work this replica owned
        # before its last restart. Closes the redeploy gap to <1s
        # instead of waiting up to LEASE_TTL_S for the sweeper.
        try:
            from shared.reclaim import reclaim_for_replica
            if self._heartbeat is not None:
                n = await reclaim_for_replica(
                    replica_id=self._heartbeat.replica_id,
                    worker_uuid=self._heartbeat.worker_uuid,
                )
                if n > 0:
                    print(f"[{self.worker_id}] [RECLAIM] {n} work items re-released for sweeper")
        except Exception as exc:
            print(f"[{self.worker_id}] startup reclaim failed (continuing): {exc}")

    async def start(self):
        """Start consuming from all backup queues"""
        await self.initialize()

        # NOTE: prefetch is now applied per-queue inside consume_queue() by
        # opening a dedicated channel per queue and calling set_qos on it.
        # The previous global override here (set_qos(prefetch_count=2) on
        # the shared publishing channel) silently capped every queue at
        # prefetch=2 because aio_pika's default global_=False makes set_qos
        # apply per-consumer-on-the-channel — and we had one consumer per
        # queue on one shared channel, so each queue got 2. Cluster-wide
        # this paced parent-job throughput at (replicas × 2) regardless of
        # the per-queue values listed below. Per-queue channels let
        # urgent/high/normal/low/heavy/partition lanes each carry their
        # intended prefetch independently. See consume_queue() below.

        # Per-queue prefetch.
        # Urgent = manually triggered backups (Teams chats, mailboxes). Each
        # chat backup's getAllMessages can take 10+ min. Prefetch=1 forces
        # round-robin across replicas so one slow chat can't starve the others.
        # Higher-throughput queues stay generous since their items are smaller.
        #
        # BACKUP_WORKER_DEDICATED_ONLY=true → this replica ONLY consumes
        # self._backup_queue_name (its dedicated lane). Used by the heavy
        # pool so it can't steal backup.urgent/high/low away from the light
        # pool. With both pools sharing those queues, RabbitMQ delivers to
        # whichever consumer subscribed first (heavy at boot), so the light
        # pool sits idle while heavy serializes its prefetch buffer through
        # 100 in-app slots — observed end-to-end on Railway. Setting the
        # flag splits the pools cleanly: routing decisions (heavy types vs
        # urgent) happen at publish-time (see shared/export_routing.py).
        #
        # Default: auto-true when this worker IS the heavy pool (its queue
        # equals BACKUP_HEAVY_QUEUE / backup.heavy). The light pool still
        # multiplexes urgent/high/normal/low. The env var still works as
        # an explicit override either way.
        _is_heavy_replica = (
            self._backup_queue_name
            == os.getenv("BACKUP_HEAVY_QUEUE", "backup.heavy")
        )
        _default_dedicated = "true" if _is_heavy_replica else "false"
        dedicated_only = os.getenv(
            "BACKUP_WORKER_DEDICATED_ONLY", _default_dedicated
        ).lower() in ("true", "1", "yes")
        if dedicated_only:
            queues = [(self._backup_queue_name, 20)]
            print(
                f"[{self.worker_id}] BACKUP_WORKER_DEDICATED_ONLY=true — "
                f"consuming ONLY {self._backup_queue_name}"
            )
        else:
            # Per-queue prefetch defaults (2026-05-17 prod tuning,
            # sized for the 8-light + 4-heavy Railway Pro fleet):
            #
            # backup.urgent (1 → 8): manual user-triggered backups.
            #   Original prefetch=1 was set to keep one slow chat from
            #   starving the others. That rationale is obsolete now that
            #   consume_queue (faa67e1) dispatches each delivery to its
            #   own task — a slow user no longer pins the replica.
            #   With 8 light replicas this lands 64 concurrent (8×8),
            #   comfortably covering a 50-user manual burst with ~25%
            #   headroom. Per-replica memory at 8 concurrent USER_CHATS:
            #   ~8 × 800 MB peak = 6-8 GB out of Railway Pro's 32 GB.
            #
            # backup.high (5 → 10): scheduled bulk triggers. Across
            #   8 light replicas = 80 concurrent. Handles a fleet-wide
            #   5K-user scheduled run as ~63 waves of 80, well within
            #   the 8h window.
            #
            # backup.low (50 → 50): unchanged — already amply sized;
            #   this lane is for retention sweeps where latency is fine.
            #
            # Each value still env-overridable; production may further
            # raise via BACKUP_URGENT_PREFETCH / BACKUP_HIGH_PREFETCH.
            queues = [
                ("backup.urgent", int(os.getenv("BACKUP_URGENT_PREFETCH", "8"))),
                ("backup.high", int(os.getenv("BACKUP_HIGH_PREFETCH", "10"))),
                (self._backup_queue_name, int(os.getenv("BACKUP_NORMAL_PREFETCH", "20"))),
                ("backup.low", int(os.getenv("BACKUP_LOW_PREFETCH", "50"))),
            ]
        # OneDrive partition lane — both the light and heavy pools
        # subscribe so any free replica can drain a shard. Prefetch=2
        # keeps each replica's in-flight shard count modest (a shard
        # may hold several GB of file work and saturate one replica
        # on its own); RMQ's fair-share dispatch distributes the
        # remaining queued shards across the rest of the pool.
        if settings.ONEDRIVE_PARTITION_ENABLED:
            queues.append(("backup.onedrive_partition", 2))
        # Chats partition lane — I/O-light, higher prefetch is fine.
        # Bumped 4 → 8 (perf #D 2026-05-17): now that consume_queue
        # actually runs handlers concurrently up to the prefetch budget
        # (previously serialized inside the iterator), an 8-way lane lets
        # each replica drain 8 chat-partition shards in parallel. With
        # 6 replicas that's 48 concurrent shards cluster-wide — enough
        # to cover 9 users × 4 shards = 36 in one wave.
        if getattr(settings, "CHATS_PARTITION_ENABLED", False):
            # 8 → 12 (2026-05-17 prod tuning). With 8 light replicas
            # this gives 96 concurrent partition shards cluster-wide.
            # A 5K-user run at MIN_CHATS=25 generates ~9.5K shards
            # (avg 2 shards/user) → ~99 waves of 96, well inside the
            # 8h window even at 90s/shard.
            queues.append(("backup.chats_partition", int(
                os.getenv("BACKUP_CHATS_PARTITION_PREFETCH", "12"),
            )))
        # Mail partition lane — many small folder drains per shard.
        # Bumped 2 → 4 (perf #D): same reason as chats. Mail shards are
        # small-IO so a few in-flight per replica is fine.
        if getattr(settings, "MAIL_PARTITION_ENABLED", False):
            queues.append(("backup.mail_partition", int(
                os.getenv("BACKUP_MAIL_PARTITION_PREFETCH", "4"),
            )))
        # SharePoint partition lane — drive shards are I/O-heavy.
        # Kept at 2: SP drives can be many GB per shard, OOM risk if we
        # stack too many on one replica.
        if getattr(settings, "SP_PARTITION_ENABLED", False):
            queues.append(("backup.sharepoint_partition", int(
                os.getenv("BACKUP_SP_PARTITION_PREFETCH", "2"),
            )))
        # Groups (Teams channels) partition lane — fat-team channel
        # shards. Channels carry message + reply payloads but most are
        # smaller per-shard than SP drives.
        # Bumped 2 → 4 (perf #D).
        if getattr(settings, "GROUPS_PARTITION_ENABLED", False):
            queues.append(("backup.groups_partition", int(
                os.getenv("BACKUP_GROUPS_PARTITION_PREFETCH", "4"),
            )))
        # Entra directory partition lane — directory-category shards.
        # Most categories are I/O-light (one Graph page each) but the
        # Groups category fans out to per-group owner+member calls.
        # Bumped 2 → 4 (perf #D).
        if getattr(settings, "ENTRA_PARTITION_ENABLED", False):
            queues.append(("backup.entra_partition", int(
                os.getenv("BACKUP_ENTRA_PARTITION_PREFETCH", "4"),
            )))

        tasks = []
        for queue_name, prefetch in queues:
            task = asyncio.create_task(self._supervised_consume(queue_name, prefetch))
            tasks.append(task)

        # OneDrive per-file retry queue consumer. Runs as a peer of the
        # RMQ consumers under the same gather so a crash here propagates
        # the same way (SIGTERM-clean shutdown still works). Gated by
        # ONEDRIVE_RETRY_QUEUE_ENABLED so operators can disable cleanly.
        if os.getenv(
            "ONEDRIVE_RETRY_QUEUE_ENABLED", "true",
        ).lower() == "true":
            tasks.append(asyncio.create_task(
                self._onedrive_retry_consumer_loop(),
            ))

        print(f"[{self.worker_id}] Started consuming from {len(queues)} queues (supervised)")
        await asyncio.gather(*tasks)

    async def _supervised_consume(self, queue_name: str, prefetch_count: int):
        """Restart-on-crash wrapper around consume_queue.

        Root cause this addresses: under the Azure SDK aiohttp transport
        cascade (`SSL shutdown timed out` / `Timeout on reading data
        from socket`), the underlying queue.iterator() can raise an
        unhandled aio-pika ChannelClosed or transport error after the
        loop's exception handler has already demoted it. That bubbles
        out of consume_queue → asyncio.gather → start() → main() and
        the worker process exits cleanly (ExitCode=0). RabbitMQ then
        redelivers the in-flight job and the new session restarts the
        whole snapshot from zero — the single biggest source of
        mid-run wasted progress documented in
        benchmarks/comparison-2026-05-11.md.

        Supervisor: catches any non-Cancelled exception, prints with
        backoff, re-enters consume_queue. Cancellation is honored so
        SIGTERM still shuts the worker down cleanly.
        """
        attempt = 0
        while True:
            try:
                await self.consume_queue(queue_name, prefetch_count)
                # consume_queue returning normally = channel closed
                # cleanly (e.g. during shutdown). Don't restart unless
                # there's still a usable channel.
                if not message_bus.channel or message_bus.channel.is_closed:
                    print(f"[{self.worker_id}] {queue_name} consumer exited; channel closed — stopping supervisor")
                    return
                print(f"[{self.worker_id}] {queue_name} consumer returned without error; restarting")
            except asyncio.CancelledError:
                raise
            except Exception as exc:
                attempt += 1
                # Exponential backoff capped at 30s so a persistently
                # broken broker doesn't spin-loop CPU, but a transient
                # transport blip recovers within seconds.
                delay = min(30, 2 ** min(attempt, 5))
                print(
                    f"[{self.worker_id}] {queue_name} consumer crashed "
                    f"(attempt {attempt}, restarting in {delay}s): "
                    f"{exc.__class__.__name__}: {exc}"
                )
                import traceback
                traceback.print_exc()
                await asyncio.sleep(delay)
                # Re-establish the broker connection if it's dropped
                # before re-entering consume_queue.
                try:
                    if not message_bus.connection or message_bus.connection.is_closed:
                        print(f"[{self.worker_id}] reconnecting message bus before {queue_name} restart")
                        await message_bus.connect()
                except Exception as reconnect_exc:
                    print(f"[{self.worker_id}] reconnect failed: {reconnect_exc} — will retry on next loop")
                    continue
            else:
                # Successful return path: brief pause before re-listening
                # to avoid hot-spin if the channel keeps closing.
                await asyncio.sleep(1)

    async def consume_queue(self, queue_name: str, prefetch_count: int):
        if not message_bus.connection or message_bus.connection.is_closed:
            return

        # Per-queue channel so set_qos(prefetch_count=N) actually scopes to
        # this consumer only. A shared channel forces every consumer to the
        # last set_qos call (because aio_pika defaults global_=False — "per
        # consumer on this channel"), which made the per-queue prefetch
        # values dead code. With one channel per queue:
        #   urgent      → prefetch=1   (fairness, slow user-initiated jobs)
        #   high        → prefetch=5
        #   dedicated   → prefetch=20  (was effectively 2 before this fix)
        #   low         → prefetch=50
        #   *_partition → prefetch=2/4 per partition lane comments above
        # That lifts the per-replica in-flight cap on the dedicated lane
        # from 2 → 20 (10× headroom), unblocking parent-job parallelism on
        # both light and heavy pools.
        channel = await message_bus.connection.channel()
        await channel.set_qos(prefetch_count=prefetch_count)
        queue = await channel.get_queue(queue_name)
        print(
            f"[{self.worker_id}] Listening on {queue_name} "
            f"(prefetch={prefetch_count})..."
        )

        # Graph-rate-limit priority is derived from the queue: a single
        # backup-worker handles backup.urgent (HIGH) + backup.normal
        # (NORMAL) concurrently; each job's Graph calls run at its
        # queue's priority via the ContextVar scope. See
        # shared/graph_priority.py for the queue→priority map.
        from shared.graph_client import graph_priority
        from shared.graph_priority import priority_for_queue
        queue_priority = priority_for_queue(queue_name)

        # Concurrent-handler refactor (perf #user-chats 2026-05-17):
        # The previous shape — `async for message: await process; await ack` —
        # serialized message processing within ONE consumer. Even though we
        # told the broker prefetch=N, we awaited each handler before
        # pulling the next message from the iterator, so each replica
        # effectively ran one message at a time per queue.
        #
        # Observable symptom: USER_CHATS shards ran user-by-user on each
        # replica (Hemant → Gajraj → Rashmi …) instead of in parallel,
        # leaving the prefetch budget idle and the chat-partition queue
        # under-utilised.
        #
        # New shape: each delivery is dispatched to a detached
        # asyncio.Task. A semaphore equal to prefetch_count caps concurrent
        # in-flight tasks so the iterator naturally pauses when full;
        # aio_pika's broker-level prefetch already limits unacked messages
        # to the same number, so we match the two budgets exactly.
        # ack/reject still happens inside each task; idempotency on crash
        # is unchanged (RMQ redelivers any unacked message).
        handler_sem = asyncio.Semaphore(max(1, prefetch_count))
        in_flight: "set[asyncio.Task]" = set()

        async def _handle_one(message) -> None:
            try:
                try:
                    body = json.loads(message.body.decode())
                    with graph_priority(queue_priority):
                        await self.process_backup_message(body)
                    await message.ack()
                except PoisonMessageError as e:
                    # Structurally invalid envelope — never retryable.
                    # Skip the delivery-count gate and route straight to
                    # DLQ so one bad payload can't pin a consumer.
                    print(
                        f"[{self.worker_id}] poison message ({e}) — "
                        f"routing to DLQ without retry"
                    )
                    try:
                        await message.reject(requeue=False)
                    except Exception:
                        pass
                except Exception as e:
                    print(f"[{self.worker_id}] Error: {e}")
                    import traceback
                    traceback.print_exc()
                    try:
                        # Check delivery count to prevent infinite requeue
                        headers = message.headers or {}
                        delivery_count = headers.get("x-delivery-count", 0)
                        if delivery_count < settings.MAX_RETRIES:
                            await message.reject(requeue=True)
                        else:
                            print(
                                f"[{self.worker_id}] Message exceeded "
                                f"max retries ({settings.MAX_RETRIES}), "
                                f"routing to DLQ"
                            )
                            await message.reject(requeue=False)
                    except Exception:
                        pass
            finally:
                handler_sem.release()

        try:
            async with queue.iterator() as queue_iter:
                async for message in queue_iter:
                    # Block here only when we already have prefetch_count
                    # handlers running. As soon as one finishes (acks /
                    # rejects), the sem releases and we pick up the next
                    # message immediately.
                    await handler_sem.acquire()
                    task = asyncio.create_task(_handle_one(message))
                    in_flight.add(task)
                    task.add_done_callback(in_flight.discard)
                    if len(in_flight) >= max(2, prefetch_count // 2):
                        # Periodic visibility: log only when concurrent
                        # in-flight count crosses the half-prefetch mark
                        # so steady-state at low load stays quiet but a
                        # saturated worker is observable.
                        if len(in_flight) % max(1, prefetch_count // 4) == 0:
                            print(
                                f"[{self.worker_id}] [PERF] {queue_name} "
                                f"in_flight={len(in_flight)}/{prefetch_count}"
                            )
        finally:
            # Drain any still-running handlers so they get a chance to
            # ack/reject before the channel closes. Without this an in-
            # flight task could be killed mid-execute, leaving the
            # message unacked AND the channel torn down so we can't
            # reject it cleanly — RMQ would redeliver via delivery-
            # count, but draining is the polite shutdown.
            if in_flight:
                try:
                    print(
                        f"[{self.worker_id}] consume_queue({queue_name}) "
                        f"draining {len(in_flight)} in-flight handler(s) "
                        f"before channel close"
                    )
                    await asyncio.gather(*in_flight, return_exceptions=True)
                except Exception:
                    pass
            # Close the per-queue channel on supervisor restart so we
            # don't leak channels each time the iterator exits. Connection
            # stays open (shared by message_bus for publishes).
            try:
                if not channel.is_closed:
                    await channel.close()
            except Exception:
                pass

    async def _emit_backup_audit(
        self,
        action: str,
        outcome: str,
        tenant,
        resource,
        snapshot,
        job_id,
        details: Optional[Dict[str, Any]] = None,
    ) -> None:
        # Fire-and-forget lifecycle audit for mass-backup sub-handlers.
        # _process_single_backup inlines the same 3 emissions; mass paths
        # use this helper so every resource backup has start/end coverage
        # regardless of which dispatch path it took. Wrapped so a slow or
        # down audit-service never masks the real backup outcome.
        #
        # `snapshot` may be the live Snapshot ORM row OR a raw str/UUID —
        # mass-path completion emits don't carry the ORM row back out of
        # the inner closure, just its id captured earlier.
        try:
            resource_type = (
                resource.type.value if hasattr(resource.type, "value")
                else str(resource.type)
            )
            if snapshot is None:
                snap_id = None
            elif hasattr(snapshot, "id"):
                snap_id = str(snapshot.id)
            else:
                snap_id = str(snapshot)
            await self.audit_logger.log(
                action=action,
                tenant_id=str(tenant.id) if tenant else None,
                org_id=(
                    str(tenant.org_id)
                    if tenant and getattr(tenant, "org_id", None)
                    else None
                ),
                actor_type="WORKER",
                resource_id=str(resource.id),
                resource_type=resource_type,
                resource_name=(
                    resource.display_name or getattr(resource, "email", None)
                    or str(resource.id)
                ),
                outcome=outcome,
                job_id=str(job_id),
                snapshot_id=snap_id,
                details=details or {},
            )
        except Exception as audit_err:
            print(f"[{self.worker_id}] [AuditLogger] lifecycle emit failed: {audit_err}")

    async def _load_mail_folder_deltas(
        self, resource_id: uuid.UUID,
    ) -> Dict[str, str]:
        """Read all per-folder delta tokens for one mailbox resource.

        Replaces the JSON-dict read from
        `resource.extra_data["mail_delta_tokens_by_folder"]` with a
        single SELECT against the new `mail_folder_delta` table.
        Returns `{folder_id: delta_token}` — same shape as the old
        dict so call sites don't need to change. Empty dict if the
        resource has no rows yet (first run / pre-migration).
        """
        try:
            async with async_session_factory() as session:
                rows = (await session.execute(
                    text(
                        """
                        SELECT folder_id, delta_token
                          FROM mail_folder_delta
                         WHERE resource_id = :rid
                        """
                    ),
                    {"rid": str(resource_id)},
                )).fetchall()
            return {str(r[0]): str(r[1]) for r in rows if r[1]}
        except Exception as e:
            # Table may not exist on a stale deploy; fail open with
            # an empty dict so the caller falls back to extra_data.
            print(
                f"[{self.worker_id}] [mail_delta] load failed for "
                f"resource={resource_id}: {type(e).__name__}: {e}"
            )
            return {}

    async def _upsert_mail_folder_delta(
        self, resource_id: uuid.UUID, folder_id: str, delta_token: str,
    ) -> None:
        """Atomic per-row UPSERT of one folder's delta token.

        Replaces the unsafe Read-Modify-Write on the JSON dict in
        `resource.extra_data`. Two concurrent folder drains finishing
        at the same time used to clobber each other; with this row
        being the only thing they touch, PG's row lock makes the two
        writes commute.
        """
        try:
            async with async_session_factory() as session:
                await session.execute(
                    text(
                        """
                        INSERT INTO mail_folder_delta
                            (resource_id, folder_id, delta_token, updated_at)
                        VALUES (:rid, :fid, :tok, NOW())
                        ON CONFLICT (resource_id, folder_id) DO UPDATE
                           SET delta_token = EXCLUDED.delta_token,
                               updated_at  = NOW()
                        """
                    ),
                    {"rid": str(resource_id), "fid": folder_id,
                     "tok": delta_token},
                )
                await session.commit()
        except Exception as e:
            # Don't fail the snapshot over the delta-token persist.
            # The legacy extra_data write still happens; this row is
            # the authoritative read path going forward.
            print(
                f"[{self.worker_id}] [mail_delta] upsert failed "
                f"(resource={resource_id}, folder={folder_id[:8] if folder_id else 'NA'}): "
                f"{type(e).__name__}: {e}"
            )

    @staticmethod
    def _should_clear_mail_deltas(full_backup: bool) -> bool:
        """A forced full must re-enumerate; clear saved per-folder deltas
        first so the drain does not resume from an old deltaLink."""
        return bool(full_backup)

    async def _clear_mail_folder_deltas(self, resource_id: uuid.UUID) -> int:
        """Delete all `mail_folder_delta` rows for a resource and strip the
        legacy `extra_data['mail_delta_tokens_by_folder']` mirror, so a
        forced full backup truly re-enumerates every folder. Idempotent;
        returns the number of delta rows removed. Fails open (returns 0)
        rather than aborting the snapshot."""
        try:
            async with async_session_factory() as session:
                res = await session.execute(
                    text(
                        "DELETE FROM mail_folder_delta WHERE resource_id = :rid"
                    ),
                    {"rid": str(resource_id)},
                )
                # JSONB minus-key drops the legacy mirror if present.
                await session.execute(
                    text(
                        "UPDATE resources "
                        "SET extra_data = extra_data - 'mail_delta_tokens_by_folder' "
                        "WHERE id = :rid "
                        "  AND extra_data ? 'mail_delta_tokens_by_folder'"
                    ),
                    {"rid": str(resource_id)},
                )
                await session.commit()
                return int(res.rowcount or 0)
        except Exception as e:
            print(
                f"[{self.worker_id}] [mail_delta] clear failed for "
                f"resource={resource_id}: {type(e).__name__}: {e}"
            )
            return 0

    @staticmethod
    def _plan_mail_date_buckets(
        *, window_start, window_end, total_bytes, target_bytes,
        max_subshards, overlap_seconds: int = 1,
    ):
        """Split [window_start, window_end] into N receivedDateTime ranges
        for parallel intra-folder backfill.

        N = clamp(ceil(total_bytes / target_bytes), 1, max_subshards).
        Buckets tile the window edge-to-edge; every bucket after the first
        is widened *backwards* by overlap_seconds so adjacent buckets
        OVERLAP and never leave a gap (invariant #3 — combined with the
        idempotent message upsert, overlap is a harmless dedupe while a gap
        would lose mail). Degenerate windows / zero bytes → a single bucket
        spanning the whole window. Returns [(start, end), ...] ascending.
        """
        import math
        from datetime import timedelta
        if window_end <= window_start or total_bytes <= 0:
            return [(window_start, window_end)]
        n = max(1, min(
            int(max_subshards),
            math.ceil(total_bytes / max(int(target_bytes), 1)),
        ))
        if n == 1:
            return [(window_start, window_end)]
        span = (window_end - window_start) / n
        eps = timedelta(seconds=overlap_seconds)
        out = []
        for i in range(n):
            s = window_start + span * i
            e = window_end if i == n - 1 else window_start + span * (i + 1)
            if i > 0:
                s = s - eps  # widen back → overlap, never gap
            out.append((s, e))
        return out

    @staticmethod
    def _should_intra_folder_subshard(
        *, enabled, size_bytes, prev_size_bytes, saved_token,
        min_bytes, jump_bytes,
    ) -> bool:
        """Decide whether to parallelize one folder's drain.

        Full backup (no saved_token): sub-shard if the folder is >= min_bytes.
        Incremental (saved_token present): sub-shard only when the per-folder
        size jump since the last baseline is >= jump_bytes (a 'big jump').
        Small incrementals take the cheap serial delta walk. Disabled flag
        short-circuits to the legacy path (byte-identical behavior).
        """
        if not enabled:
            return False
        if not saved_token:
            return int(size_bytes or 0) >= int(min_bytes)
        return (int(size_bytes or 0) - int(prev_size_bytes or 0)) >= int(jump_bytes)

    @staticmethod
    def _chat_sparse_skip_writes(enabled: bool, has_prior_snapshot: bool) -> bool:
        """Return True if an UNCHANGED chat should write ZERO pointer rows
        (sparse) and rely on the sibling-snapshot union to reconstruct it.

        Only safe when a prior COMPLETED snapshot exists for the resource —
        that's what the union (created_at<=picked, newest-wins) reads from.
        With no prior, we must write the full inventory (first backup)."""
        return bool(enabled) and bool(has_prior_snapshot)

    async def _chat_resource_has_completed_snapshot(
        self, resource_id: uuid.UUID,
    ) -> bool:
        """True if this USER_CHATS resource already has a COMPLETED snapshot
        (the current run's snapshot is still IN_PROGRESS, so it's excluded).
        Gate for sparse chat incrementals: the sibling-union can only
        reconstruct an unchanged chat if an earlier completed snapshot holds
        its rows. Fails CLOSED (False → write full) on any error."""
        try:
            async with async_session_factory() as session:
                row = (await session.execute(
                    text(
                        "SELECT EXISTS(SELECT 1 FROM snapshots "
                        "WHERE resource_id = :rid AND status = 'COMPLETED')"
                    ),
                    {"rid": str(resource_id)},
                )).scalar()
            return bool(row)
        except Exception as e:
            print(
                f"[{self.worker_id}] [USER_CHATS] prior-snapshot check "
                f"failed for {resource_id}: {type(e).__name__}: {e} "
                f"— writing full inventory (safe)"
            )
            return False

    async def _chat_user_all_unchanged(
        self, tenant_id: str, chat_last_updated_map: Dict[str, str],
        chat_ids: List[str],
    ) -> bool:
        """True iff EVERY chat in `chat_ids` is unchanged since we last
        drained it — the SAME signal the per-chat activity-skip trusts
        (chat.lastUpdatedDateTime <= its saved drain_cursor), evaluated
        up-front for the whole user so we can skip the entire per-chat loop.

        Fails CLOSED (returns False → normal full drain) on ANY of: a chat
        with no saved cursor (never drained / brand-new), a deltaLink-style
        (http) cursor we can't string-compare, a missing lastUpdatedDateTime,
        a chat whose lastUpdatedDateTime is AFTER its cursor (real activity),
        or any error. So a new message anywhere → full drain → never missed."""
        if not chat_ids:
            return False
        try:
            from sqlalchemy import bindparam
            stmt = text(
                "SELECT chat_id, drain_cursor FROM chat_threads "
                "WHERE tenant_id = :tid AND chat_id IN :cids"
            ).bindparams(bindparam("cids", expanding=True))
            async with async_session_factory() as session:
                rows = (await session.execute(
                    stmt, {"tid": tenant_id, "cids": list(chat_ids)},
                )).all()
            cursors = {r[0]: r[1] for r in rows}
            for cid in chat_ids:
                cur = cursors.get(cid)
                if not cur or str(cur).startswith("http"):
                    return False  # never drained / deltalink → can't prove unchanged
                lu = chat_last_updated_map.get(cid)
                if not lu or str(lu) > str(cur):
                    return False  # new activity (or unknown) → changed
            return True
        except Exception as e:
            print(
                f"[{self.worker_id}] [USER_CHATS] user-level skip check "
                f"failed (tenant={tenant_id}): {type(e).__name__}: {e} "
                f"— full drain (safe)"
            )
            return False

    async def _load_mail_folder_fingerprints(
        self, resource_id: uuid.UUID,
    ) -> Dict[str, Dict[str, Any]]:
        """Read all per-folder fingerprints for one mailbox resource.

        Returns `{folder_id: {"fp": "total|unread|size", "baseline_at": dt}}`.
        Replaces the whole-mailbox JSON dict at
        `resource.extra_data["mail_folder_fingerprints"]`. The dict
        was unsafe under partition fanout: sibling shards' writes
        for folders this shard didn't own clobbered each other and
        caused skip-by-fp to skip the entire allowlist. Per-row state
        makes the writes commute. Empty dict on first run / table
        miss; the caller falls back to the legacy dict during the
        dual-read transition.
        """
        try:
            async with async_session_factory() as session:
                rows = (await session.execute(
                    text(
                        """
                        SELECT folder_id, total_item_count,
                               unread_item_count, size_in_bytes,
                               baseline_at
                          FROM mail_folder_fingerprint
                         WHERE resource_id = :rid
                        """
                    ),
                    {"rid": str(resource_id)},
                )).fetchall()
            return {
                str(r[0]): {
                    "fp": f"{int(r[1])}|{int(r[2])}|{int(r[3])}",
                    "baseline_at": r[4],
                }
                for r in rows
            }
        except Exception as e:
            # Table may not exist on a stale deploy; fail open so the
            # caller falls back to extra_data.mail_folder_fingerprints.
            print(
                f"[{self.worker_id}] [mail_fp] load failed for "
                f"resource={resource_id}: {type(e).__name__}: {e}"
            )
            return {}

    async def _upsert_mail_folder_fingerprint(
        self,
        resource_id: uuid.UUID,
        folder_id: str,
        total: int,
        unread: int,
        size: int,
    ) -> None:
        """Atomic per-row UPSERT of one folder's fingerprint.

        `baseline_at` advances to NOW() on every successful UPSERT;
        the 3-day full-rescan window is therefore per folder, not
        mailbox-wide.
        """
        try:
            async with async_session_factory() as session:
                await session.execute(
                    text(
                        """
                        INSERT INTO mail_folder_fingerprint
                            (resource_id, folder_id,
                             total_item_count, unread_item_count,
                             size_in_bytes, baseline_at)
                        VALUES (:rid, :fid, :t, :u, :s, NOW())
                        ON CONFLICT (resource_id, folder_id) DO UPDATE
                           SET total_item_count  = EXCLUDED.total_item_count,
                               unread_item_count = EXCLUDED.unread_item_count,
                               size_in_bytes     = EXCLUDED.size_in_bytes,
                               baseline_at       = NOW()
                        """
                    ),
                    {"rid": str(resource_id), "fid": folder_id,
                     "t": int(total), "u": int(unread), "s": int(size)},
                )
                await session.commit()
        except Exception as e:
            print(
                f"[{self.worker_id}] [mail_fp] upsert failed "
                f"(resource={resource_id}, folder={folder_id[:8] if folder_id else 'NA'}): "
                f"{type(e).__name__}: {e}"
            )

